#[derive(Clone, Copy)]
enum DataViewElementKind {
  Int8,
  Uint8,
  Int16,
  Uint16,
  Int32,
  Uint32,
  Float16,
  Float32,
  Float64,
}

impl DataViewElementKind {
  fn size(self) -> usize {
    match self {
      DataViewElementKind::Int8 | DataViewElementKind::Uint8 => 1,
      DataViewElementKind::Int16 | DataViewElementKind::Uint16 | DataViewElementKind::Float16 => 2,
      DataViewElementKind::Int32 | DataViewElementKind::Uint32 | DataViewElementKind::Float32 => 4,
      DataViewElementKind::Float64 => 8,
    }
  }
}

fn data_view_get_impl(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  this: Value,
  args: &[Value],
  kind: DataViewElementKind,
) -> Result<Value, VmError> {
  let Value::Object(view_obj) = this else {
    return Err(VmError::TypeError("DataView method called on non-object"));
  };
  // Root the receiver + arguments before any potential GC triggered by rooting itself. Host
  // callers may invoke this builtin without pre-rooting the handles.
  let offset_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let little_endian_val = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_roots(&[Value::Object(view_obj), offset_val, little_endian_val])?;
  let byte_length = scope
    .heap()
    .data_view_byte_length_slot(view_obj)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;
  let view_byte_offset = scope
    .heap()
    .data_view_byte_offset_slot(view_obj)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;
  let buffer = scope
    .heap()
    .data_view_buffer(view_obj)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;

  let offset = to_index_from_value(vm, scope, host, hooks, offset_val)?;

  let little_endian = match little_endian_val {
    Value::Undefined => false,
    v => scope.heap().to_boolean(v)?,
  };

  // Spec: detached ArrayBuffer check happens after ToIndex(byteOffset).
  if scope
    .heap()
    .is_detached_array_buffer(buffer)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?
  {
    return Err(VmError::TypeError("ArrayBuffer is detached"));
  }
  let buffer_byte_length = scope
    .heap()
    .array_buffer_byte_length(buffer)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;
  let view_end = view_byte_offset
    .checked_add(byte_length)
    .ok_or(VmError::TypeError("DataView view out of bounds"))?;
  if view_end > buffer_byte_length {
    return Err(VmError::TypeError("DataView view out of bounds"));
  }

  let size = kind.size();
  let end = offset
    .checked_add(size)
    .ok_or(VmError::RangeError("DataView offset out of bounds"))?;
  if end > byte_length {
    return Err(VmError::RangeError("DataView offset out of bounds"));
  }

  scope.push_root(Value::Object(buffer))?;
  let data = scope.heap().array_buffer_data(buffer)?;
  let abs = view_byte_offset
    .checked_add(offset)
    .ok_or(VmError::OutOfMemory)?;

  let value = match kind {
    DataViewElementKind::Int8 => {
      let b = *data.get(abs).ok_or(VmError::TypeError("DataView offset out of bounds"))?;
      (b as i8) as f64
    }
    DataViewElementKind::Uint8 => {
      let b = *data.get(abs).ok_or(VmError::TypeError("DataView offset out of bounds"))?;
      b as f64
    }
    DataViewElementKind::Int16 => {
      let bytes: [u8; 2] = data
        .get(abs..abs + 2)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      if little_endian {
        i16::from_le_bytes(bytes) as f64
      } else {
        i16::from_be_bytes(bytes) as f64
      }
    }
    DataViewElementKind::Uint16 => {
      let bytes: [u8; 2] = data
        .get(abs..abs + 2)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      if little_endian {
        u16::from_le_bytes(bytes) as f64
      } else {
        u16::from_be_bytes(bytes) as f64
      }
    }
    DataViewElementKind::Int32 => {
      let bytes: [u8; 4] = data
        .get(abs..abs + 4)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      if little_endian {
        i32::from_le_bytes(bytes) as f64
      } else {
        i32::from_be_bytes(bytes) as f64
      }
    }
    DataViewElementKind::Uint32 => {
      let bytes: [u8; 4] = data
        .get(abs..abs + 4)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      if little_endian {
        u32::from_le_bytes(bytes) as f64
      } else {
        u32::from_be_bytes(bytes) as f64
      }
    }
    DataViewElementKind::Float16 => {
      let bytes: [u8; 2] = data
        .get(abs..abs + 2)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      let bits = if little_endian {
        u16::from_le_bytes(bytes)
      } else {
        u16::from_be_bytes(bytes)
      };
      f16_bits_to_f64(bits)
    }
    DataViewElementKind::Float32 => {
      let bytes: [u8; 4] = data
        .get(abs..abs + 4)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      let bits = if little_endian {
        u32::from_le_bytes(bytes)
      } else {
        u32::from_be_bytes(bytes)
      };
      f32::from_bits(bits) as f64
    }
    DataViewElementKind::Float64 => {
      let bytes: [u8; 8] = data
        .get(abs..abs + 8)
        .ok_or(VmError::TypeError("DataView offset out of bounds"))?
        .try_into()
        .map_err(|_| VmError::InvariantViolation("DataView slice length mismatch"))?;
      let bits = if little_endian {
        u64::from_le_bytes(bytes)
      } else {
        u64::from_be_bytes(bytes)
      };
      f64::from_bits(bits)
    }
  };

  Ok(Value::Number(value))
}

fn data_view_set_impl(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  this: Value,
  args: &[Value],
  kind: DataViewElementKind,
) -> Result<Value, VmError> {
  let Value::Object(view_obj) = this else {
    return Err(VmError::TypeError("DataView method called on non-object"));
  };
  // Root the receiver + arguments before any potential GC triggered by rooting itself. Host
  // callers may invoke this builtin without pre-rooting the handles.
  let offset_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let value = args.get(1).copied().unwrap_or(Value::Undefined);
  let little_endian_val = args.get(2).copied().unwrap_or(Value::Undefined);
  scope.push_roots(&[Value::Object(view_obj), offset_val, value, little_endian_val])?;
  let byte_length = scope
    .heap()
    .data_view_byte_length_slot(view_obj)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;
  let view_byte_offset = scope
    .heap()
    .data_view_byte_offset_slot(view_obj)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;
  let buffer = scope
    .heap()
    .data_view_buffer(view_obj)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;

  // Spec: `SetViewValue` must reject immutable buffers *before* converting `byteOffset`/`value`
  // arguments.
  if scope
    .heap()
    .array_buffer_is_immutable(buffer)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?
  {
    return Err(VmError::TypeError("ArrayBuffer is immutable"));
  }

  let offset = to_index_from_value(vm, scope, host, hooks, offset_val)?;

  // Convert via ToNumber (like typed arrays). Spec: `SetViewValue` performs value coercion before
  // checking for detached/out-of-bounds views.
  let n = scope.to_number(vm, host, hooks, value)?;

  let little_endian = match little_endian_val {
    Value::Undefined => false,
    v => scope.heap().to_boolean(v)?,
  };

  // Spec: detached ArrayBuffer check happens after ToIndex(byteOffset).
  if scope
    .heap()
    .is_detached_array_buffer(buffer)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?
  {
    return Err(VmError::TypeError("ArrayBuffer is detached"));
  }
  let buffer_byte_length = scope
    .heap()
    .array_buffer_byte_length(buffer)
    .map_err(|_| VmError::TypeError("DataView method called on incompatible receiver"))?;
  let view_end = view_byte_offset
    .checked_add(byte_length)
    .ok_or(VmError::TypeError("DataView view out of bounds"))?;
  if view_end > buffer_byte_length {
    return Err(VmError::TypeError("DataView view out of bounds"));
  }

  let size = kind.size();
  let end = offset
    .checked_add(size)
    .ok_or(VmError::RangeError("DataView offset out of bounds"))?;
  if end > byte_length {
    return Err(VmError::RangeError("DataView offset out of bounds"));
  }

  let bytes: Vec<u8> = match kind {
    DataViewElementKind::Int8 => {
      let v = if !n.is_finite() { 0 } else { n.trunc().rem_euclid(256.0) as u8 as i8 };
      vec![v as u8]
    }
    DataViewElementKind::Uint8 => {
      let v = if !n.is_finite() { 0 } else { n.trunc().rem_euclid(256.0) as u8 };
      vec![v]
    }
    DataViewElementKind::Int16 => {
      let v = if !n.is_finite() { 0 } else { n.trunc().rem_euclid(65_536.0) as u16 as i16 };
      if little_endian {
        v.to_le_bytes().to_vec()
      } else {
        v.to_be_bytes().to_vec()
      }
    }
    DataViewElementKind::Uint16 => {
      let v = if !n.is_finite() { 0 } else { n.trunc().rem_euclid(65_536.0) as u16 };
      if little_endian {
        v.to_le_bytes().to_vec()
      } else {
        v.to_be_bytes().to_vec()
      }
    }
    DataViewElementKind::Int32 => {
      let v = if !n.is_finite() { 0 } else { n.trunc().rem_euclid(4_294_967_296.0) as u32 as i32 };
      if little_endian {
        v.to_le_bytes().to_vec()
      } else {
        v.to_be_bytes().to_vec()
      }
    }
    DataViewElementKind::Uint32 => {
      let v = if !n.is_finite() { 0 } else { n.trunc().rem_euclid(4_294_967_296.0) as u32 };
      if little_endian {
        v.to_le_bytes().to_vec()
      } else {
        v.to_be_bytes().to_vec()
      }
    }
    DataViewElementKind::Float16 => {
      let bits = f64_to_f16_bits_round_ties_to_even(n);
      if little_endian {
        bits.to_le_bytes().to_vec()
      } else {
        bits.to_be_bytes().to_vec()
      }
    }
    DataViewElementKind::Float32 => {
      let v = (n as f32).to_bits();
      if little_endian {
        v.to_le_bytes().to_vec()
      } else {
        v.to_be_bytes().to_vec()
      }
    }
    DataViewElementKind::Float64 => {
      let v = n.to_bits();
      if little_endian {
        v.to_le_bytes().to_vec()
      } else {
        v.to_be_bytes().to_vec()
      }
    }
  };

  debug_assert_eq!(bytes.len(), size);
  let abs = view_byte_offset
    .checked_add(offset)
    .ok_or(VmError::OutOfMemory)?;
  scope.push_root(Value::Object(buffer))?;
  scope.heap_mut().array_buffer_write(buffer, abs, &bytes)?;
  Ok(Value::Undefined)
}

macro_rules! data_view_get {
  ($name:ident, $kind:expr) => {
    pub fn $name(
      vm: &mut Vm,
      scope: &mut Scope<'_>,
      host: &mut dyn VmHost,
      hooks: &mut dyn VmHostHooks,
      _callee: GcObject,
      this: Value,
      args: &[Value],
    ) -> Result<Value, VmError> {
      data_view_get_impl(vm, scope, host, hooks, this, args, $kind)
    }
  };
}

macro_rules! data_view_set {
  ($name:ident, $kind:expr) => {
    pub fn $name(
      vm: &mut Vm,
      scope: &mut Scope<'_>,
      host: &mut dyn VmHost,
      hooks: &mut dyn VmHostHooks,
      _callee: GcObject,
      this: Value,
      args: &[Value],
    ) -> Result<Value, VmError> {
      data_view_set_impl(vm, scope, host, hooks, this, args, $kind)
    }
  };
}

