/// `Object.prototype.isPrototypeOf(V)` (ECMA-262).
pub fn object_prototype_is_prototype_of(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let v = args.get(0).copied().unwrap_or(Value::Undefined);
  let Value::Object(mut v_obj) = v else {
    // Spec note: `Object.prototype.isPrototypeOf` observes the argument type *before*
    // `ToObject(this value)` so `Object.prototype.isPrototypeOf.call(null, 1)` returns `false`
    // rather than throwing (legacy behaviour preserved by ECMA-262 ordering).
    return Ok(Value::Bool(false));
  };
  scope.push_roots(&[this, Value::Object(v_obj)])?;

  let o = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(o))?;

  let mut steps = 0usize;
  loop {
    if steps % 1024 == 0 {
      vm.tick()?;
    }
    if steps >= crate::heap::MAX_PROTOTYPE_CHAIN {
      return Err(VmError::PrototypeChainTooDeep);
    }

    // Spec uses `[[GetPrototypeOf]]`, which is Proxy-aware (trap + revoked proxy errors).
    let p = {
      let mut step_scope = scope.reborrow();
      step_scope.push_root(Value::Object(v_obj))?;
      step_scope.get_prototype_of_with_host_and_hooks(vm, host, hooks, v_obj)?
    };
    let Some(p) = p else {
      return Ok(Value::Bool(false));
    };
    if p == o {
      return Ok(Value::Bool(true));
    }
    v_obj = p;
    steps += 1;
  }
}

/// `Object.prototype.valueOf()` (ECMA-262).
pub fn object_prototype_value_of(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-object.prototype.valueof
  let obj = scope.to_object(vm, host, hooks, this)?;
  Ok(Value::Object(obj))
}

/// `Object.prototype.propertyIsEnumerable(V)` (ECMA-262).
pub fn object_prototype_property_is_enumerable(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let prop = args.get(0).copied().unwrap_or(Value::Undefined);
  let key = scope.to_property_key(vm, host, hooks, prop)?;
  root_property_key(&mut scope, key)?;

  let Some(desc) = scope.object_get_own_property_with_host_and_hooks(vm, host, hooks, obj, key)? else {
    return Ok(Value::Bool(false));
  };
  Ok(Value::Bool(desc.enumerable))
}

/// `Object.prototype.toLocaleString` (ECMA-262) (minimal).
pub fn object_prototype_to_locale_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // Spec: return ? Invoke(this, "toString")
  let mut scope = scope.reborrow();
  let receiver = scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, receiver)?;
  scope.push_root(Value::Object(obj))?;

  let to_string_key = string_key(&mut scope, "toString")?;
  let func = scope.get_with_host_and_hooks(vm, host, hooks, obj, to_string_key, receiver)?;
  if !scope.heap().is_callable(func)? {
    return Err(VmError::TypeError("toString is not callable"));
  }
  scope.push_root(func)?;

  vm.call_with_host_and_hooks(host, &mut scope, hooks, func, receiver, &[])
}

fn get_array_length(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  obj: GcObject,
) -> Result<usize, VmError> {
  length_of_array_like_usize(vm, scope, host, hooks, obj)
}

fn internal_symbol_key(scope: &mut Scope<'_>, s: &str) -> Result<PropertyKey, VmError> {
  let marker_sym = match s {
    ARRAY_ITERATOR_ARRAY_MARKER => scope.heap_mut().ensure_internal_array_iterator_array_symbol()?,
    ARRAY_ITERATOR_INDEX_MARKER => scope.heap_mut().ensure_internal_array_iterator_index_symbol()?,
    ARRAY_ITERATOR_KIND_MARKER => scope.heap_mut().ensure_internal_array_iterator_kind_symbol()?,
    MAP_ITERATOR_MAP_MARKER => scope.heap_mut().ensure_internal_map_iterator_map_symbol()?,
    MAP_ITERATOR_INDEX_MARKER => scope.heap_mut().ensure_internal_map_iterator_index_symbol()?,
    MAP_ITERATOR_KIND_MARKER => scope.heap_mut().ensure_internal_map_iterator_kind_symbol()?,
    SET_ITERATOR_SET_MARKER => scope.heap_mut().ensure_internal_set_iterator_set_symbol()?,
    SET_ITERATOR_INDEX_MARKER => scope.heap_mut().ensure_internal_set_iterator_index_symbol()?,
    SET_ITERATOR_KIND_MARKER => scope.heap_mut().ensure_internal_set_iterator_kind_symbol()?,
    _ => return Err(VmError::InvariantViolation("unknown internal symbol key")),
  };
  Ok(PropertyKey::from_symbol(marker_sym))
}

const ARRAY_ITERATOR_ARRAY_MARKER: &str = "vm-js.internal.ArrayIteratorArray";
const ARRAY_ITERATOR_INDEX_MARKER: &str = "vm-js.internal.ArrayIteratorIndex";
const ARRAY_ITERATOR_KIND_MARKER: &str = "vm-js.internal.ArrayIteratorKind";
const MAP_ITERATOR_MAP_MARKER: &str = "vm-js.internal.MapIteratorMap";
const MAP_ITERATOR_INDEX_MARKER: &str = "vm-js.internal.MapIteratorIndex";
const MAP_ITERATOR_KIND_MARKER: &str = "vm-js.internal.MapIteratorKind";
const SET_ITERATOR_SET_MARKER: &str = "vm-js.internal.SetIteratorSet";
const SET_ITERATOR_INDEX_MARKER: &str = "vm-js.internal.SetIteratorIndex";
const SET_ITERATOR_KIND_MARKER: &str = "vm-js.internal.SetIteratorKind";
const GENERATOR_STATE_MARKER: &str = "vm-js.internal.GeneratorState";

// --- Modern Array.prototype built-ins (ES2022+ / ES2023) ---

#[derive(Clone, Copy, Debug)]
enum FlattenDepth {
  Finite(u32),
  Infinite,
}

impl FlattenDepth {
  fn is_zero(self) -> bool {
    matches!(self, FlattenDepth::Finite(0))
  }

  fn dec(self) -> FlattenDepth {
    match self {
      FlattenDepth::Infinite => FlattenDepth::Infinite,
      FlattenDepth::Finite(0) => FlattenDepth::Finite(0),
      FlattenDepth::Finite(n) => FlattenDepth::Finite(n - 1),
    }
  }
}

#[derive(Clone, Copy, Debug)]
struct FlattenFrame {
  source: GcObject,
  source_len: usize,
  source_index: usize,
  depth: FlattenDepth,
  /// Whether to apply the `mapperFunction` (only true for the root `flatMap` invocation).
  apply_mapper: bool,
}

fn array_create_with_intrinsics(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  len: usize,
) -> Result<GcObject, VmError> {
  let intr = require_intrinsics(vm)?;
  let array = scope.alloc_array(len)?;
  scope
    .heap_mut()
    .object_set_prototype(array, Some(intr.array_prototype()))?;
  Ok(array)
}

// https://tc39.es/ecma262/#sec-arrayspeciescreate
fn array_species_create_with_host_and_hooks(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  original: GcObject,
  len: usize,
) -> Result<GcObject, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-arrayspeciescreate
  //
  // Note: `ArraySpeciesCreate` has cross-realm semantics that are *not* captured by a direct call to
  // `SpeciesConstructor(originalArray, %Array%)`: if `originalArray.constructor` is the `%Array%`
  // intrinsic of a different realm, it must be treated as `undefined` without consulting
  // `@@species`.

  let mut scope = scope.reborrow();
  scope.push_root(Value::Object(original))?;

  // 1. Let isArray be ? IsArray(originalArray).
  let is_array = crate::spec_ops::is_array_with_host_and_hooks(
    vm,
    &mut scope,
    host,
    hooks,
    Value::Object(original),
  )?;
  if !is_array {
    // 2. If isArray is false, return ? ArrayCreate(length).
    return array_create_with_intrinsics(vm, &mut scope, len);
  }

  // 3. Let C be ? Get(originalArray, "constructor").
  let constructor_key = string_key(&mut scope, "constructor")?;
  let mut c = scope.get_with_host_and_hooks(
    vm,
    host,
    hooks,
    original,
    constructor_key,
    Value::Object(original),
  )?;
  scope.push_root(c)?;

  // 4. If IsConstructor(C) is true, then:
  if scope.heap().is_constructor(c)? {
    // a. Let thisRealm be the current Realm Record.
    // b. Let realmC be ? GetFunctionRealm(C).
    // c. If thisRealm and realmC are not the same Realm Record, then:
    //    i. If SameValue(C, realmC.[[Intrinsics]].[[%Array%]]) is true, let C be undefined.
    let this_realm = vm.current_realm().or_else(|| vm.active_realm_state());
    let realm_c = match c {
      Value::Object(obj) => scope.heap().get_function_job_realm(obj),
      _ => None,
    };
    if let (Some(this_realm), Some(realm_c)) = (this_realm, realm_c) {
      if this_realm != realm_c {
        if let Some(intr_c) = vm.intrinsics_for_realm(realm_c) {
          if c == Value::Object(intr_c.array_constructor()) {
            c = Value::Undefined;
          }
        }
      }
    }
  }

  // 5. If Type(C) is Object, then:
  if let Value::Object(c_obj) = c {
    let species_sym = require_intrinsics(vm)?.well_known_symbols().species;
    scope.push_root(Value::Symbol(species_sym))?;
    let species_key = PropertyKey::from_symbol(species_sym);

    // a. Set C to ? Get(C, @@species).
    let mut species =
      scope.get_with_host_and_hooks(vm, host, hooks, c_obj, species_key, Value::Object(c_obj))?;
    scope.push_root(species)?;

    // b. If C is null, set C to undefined.
    if matches!(species, Value::Null) {
      species = Value::Undefined;
    }
    c = species;
  }

  // 6. If C is undefined, return ? ArrayCreate(length).
  if matches!(c, Value::Undefined) {
    return array_create_with_intrinsics(vm, &mut scope, len);
  }

  // 7. If IsConstructor(C) is false, throw a TypeError exception.
  if !scope.heap().is_constructor(c)? {
    return Err(VmError::TypeError("ArraySpeciesCreate: @@species is not a constructor"));
  }

  // 8. Return ? Construct(C, « length »).
  let constructed =
    vm.construct_with_host_and_hooks(host, &mut scope, hooks, c, &[Value::Number(len as f64)], c)?;
  let Value::Object(obj) = constructed else {
    return Err(VmError::InvariantViolation(
      "ArraySpeciesCreate: Construct did not return an object",
    ));
  };
  Ok(obj)
}

// https://tc39.es/ecma262/#sec-flattenintoarray
fn flatten_into_array(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  target: GcObject,
  source: GcObject,
  source_len: usize,
  start: usize,
  depth: FlattenDepth,
  mapper: Option<(Value, Value)>,
) -> Result<usize, VmError> {
  // `targetIndex` is specified as an integer in the range [0, 2^53 - 1).
  const MAX_SAFE_INTEGER: u64 = 9_007_199_254_740_991; // 2^53 - 1

  let mut target_index = start;

  let mut stack: Vec<FlattenFrame> = Vec::new();
  vec_try_push(
    &mut stack,
    FlattenFrame {
      source,
      source_len,
      source_index: 0,
      depth,
      apply_mapper: mapper.is_some(),
    },
  )?;

  // Budget the total number of processed source indices (across nested arrays).
  let mut steps: usize = 0;

  while let Some(frame) = stack.last_mut() {
    if frame.source_index >= frame.source_len {
      stack.pop();
      continue;
    }

    let source_index = frame.source_index;
    frame.source_index = frame.source_index.checked_add(1).ok_or(VmError::OutOfMemory)?;

    steps = steps.checked_add(1).ok_or(VmError::OutOfMemory)?;
    if steps % 1024 == 0 {
      vm.tick()?;
    }

    // Capture values needed outside the per-iteration scope.
    let mut nested_to_push: Option<FlattenFrame> = None;
    let mut nested_to_root: Option<GcObject> = None;

    {
      // Use a nested scope so per-iteration roots do not accumulate.
      let mut iter_scope = scope.reborrow();

      // `P = ToString(sourceIndex)`
      let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, source_index)?;
      iter_scope.push_root(key_root)?;

      // 1. Let exists be ? HasProperty(source, P).
      if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, frame.source, key)? {
        continue;
      }

      // 2. Let element be ? Get(source, P).
      let mut element = iter_scope.get_with_host_and_hooks(
        vm,
        host,
        hooks,
        frame.source,
        key,
        Value::Object(frame.source),
      )?;

      // 3. If mapperFunction is present, then:
      if frame.apply_mapper {
        if let Some((mapper_fn, this_arg)) = mapper {
          let call_args = [
            element,
            Value::Number(source_index as f64),
            Value::Object(frame.source),
          ];
          element = vm.call_with_host_and_hooks(
            host,
            &mut iter_scope,
            hooks,
            mapper_fn,
            this_arg,
            &call_args,
          )?;
        }
      }

      // 4. If depth > 0 and IsArray(element) is true, then:
      if !frame.depth.is_zero() {
        let is_array =
          crate::spec_ops::is_array_with_host_and_hooks(vm, &mut iter_scope, host, hooks, element)?;
        if is_array {
          let Value::Object(element_obj) = element else {
            return Err(VmError::InvariantViolation(
              "FlattenIntoArray: IsArray returned true for non-object",
            ));
          };

          // `elementLen = ? LengthOfArrayLike(element)`
          let element_len = length_of_array_like_usize(vm, &mut iter_scope, host, hooks, element_obj)?;

          nested_to_root = Some(element_obj);
          nested_to_push = Some(FlattenFrame {
            source: element_obj,
            source_len: element_len,
            source_index: 0,
            depth: frame.depth.dec(),
            // Mapper is only applied to the top-level `flatMap` invocation.
            apply_mapper: false,
          });
        }
      }

      if nested_to_push.is_none() {
      // 5. Else, append element to target.
      if (target_index as u64) >= MAX_SAFE_INTEGER {
        return Err(VmError::TypeError(
          "FlattenIntoArray target index exceeds maximum safe integer",
        ));
      }

      // Root `element` across key allocation + property definition: it can be produced by accessors
      // / mapper calls and otherwise be unreachable.
      iter_scope.push_root(element)?;

      let (to_key, to_root) = alloc_array_index_key_from_usize(&mut iter_scope, target_index)?;
      iter_scope.push_root(to_root)?;
      iter_scope.create_data_property_or_throw(target, to_key, element)?;

        target_index = target_index.checked_add(1).ok_or(VmError::OutOfMemory)?;
      }
    }

    if let Some(obj) = nested_to_root {
      // Keep nested arrays alive even if user code deletes them from the source while we're
      // flattening (e.g. via getters / Proxy traps / mapper side effects).
      scope.push_root(Value::Object(obj))?;
    }
    if let Some(frame) = nested_to_push {
      vec_try_push(&mut stack, frame)?;
    }
  }

  Ok(target_index)
}
/// `Array.prototype.at(index)` (ECMA-262).
pub fn array_prototype_at(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.at
  let mut scope = scope.reborrow();
  // Root `this` + arguments before any allocations / coercions. Host callers may invoke this
  // builtin directly without `Vm::call_impl` argument rooting.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  // `Array.prototype.at` is generic and must work on String values via `ToObject` + indexed
  // property access. `vm-js` does not currently model String exotic objects, so handle String
  // primitives (and boxed String objects created by `ToObject`) explicitly.
  //
  // Note: string indexing uses UTF-16 code unit indices (i.e. it does not decode surrogate pairs).
  let string_data = match this {
    Value::String(s) => Some(s),
    Value::Object(obj) => {
      let marker_sym = match scope.heap().internal_string_data_symbol() {
        Some(sym) => sym,
        None => scope.heap_mut().ensure_internal_string_data_symbol()?,
      };
      let marker_key = PropertyKey::from_symbol(marker_sym);
      match get_data_property_value(vm, &mut scope, obj, &marker_key)? {
        Some(Value::String(s)) => Some(s),
        _ => None,
      }
    }
    _ => None,
  };
  if let Some(s) = string_data {
    let len = scope.heap().get_string(s)?.as_code_units().len();

    let index_val = args.get(0).copied().unwrap_or(Value::Undefined);
    let relative = scope.to_integer_or_infinity(vm, host, hooks, index_val)?;
    if !relative.is_finite() {
      return Ok(Value::Undefined);
    }

    let k = if relative < 0.0 {
      (len as f64) + relative
    } else {
      relative
    };
    if k < 0.0 || k >= (len as f64) {
      return Ok(Value::Undefined);
    }

    let idx = k as usize;
    let unit = scope.heap().get_string(s)?.as_code_units()[idx];
    let out = scope.alloc_string_from_code_units(&[unit])?;
    return Ok(Value::String(out));
  }

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let index_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let relative = scope.to_integer_or_infinity(vm, host, hooks, index_val)?;

  if !relative.is_finite() {
    return Ok(Value::Undefined);
  }

  let k = if relative < 0.0 {
    (len as f64) + relative
  } else {
    relative
  };

  if k < 0.0 || k >= (len as f64) {
    return Ok(Value::Undefined);
  }

  let k_usize = k as usize;
  let (key, key_root) = alloc_array_index_key_from_usize(&mut scope, k_usize)?;
  scope.push_root(key_root)?;

  scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))
}

/// `Array.prototype.flat([depth])` (ECMA-262).
pub fn array_prototype_flat(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.flat
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`ToIntegerOrInfinity`, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let source_len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  // Spec: `depthNum = 1; if depth is not undefined, depthNum = ? ToIntegerOrInfinity(depth)`
  let depth_arg = args.get(0).copied().unwrap_or(Value::Undefined);
  let depth_num = if matches!(depth_arg, Value::Undefined) {
    1.0
  } else {
    scope.to_integer_or_infinity(vm, host, hooks, depth_arg)?
  };
  let depth = if depth_num <= 0.0 {
    FlattenDepth::Finite(0)
  } else if !depth_num.is_finite() {
    FlattenDepth::Infinite
  } else {
    let depth_u64 = depth_num as u64;
    let depth_u32 = u32::try_from(depth_u64).unwrap_or(u32::MAX);
    FlattenDepth::Finite(depth_u32)
  };

  let target = array_species_create_with_host_and_hooks(vm, &mut scope, host, hooks, obj, 0)?;
  scope.push_root(Value::Object(target))?;

  let _ = flatten_into_array(vm, &mut scope, host, hooks, target, obj, source_len, 0, depth, None)?;

  Ok(Value::Object(target))
}

/// `Array.prototype.flatMap(mapperFunction[, thisArg])` (ECMA-262).
pub fn array_prototype_flat_map(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.flatmap
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`IsCallable` checks, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let mapper_fn = args.get(0).copied().unwrap_or(Value::Undefined);
  if !scope.heap().is_callable(mapper_fn)? {
    return Err(VmError::TypeError("Array.prototype.flatMap mapper is not callable"));
  }
  scope.push_root(mapper_fn)?;

  let this_arg = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(this_arg)?;

  let source_len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let target = array_species_create_with_host_and_hooks(vm, &mut scope, host, hooks, obj, 0)?;
  scope.push_root(Value::Object(target))?;

  let _ = flatten_into_array(
    vm,
    &mut scope,
    host,
    hooks,
    target,
    obj,
    source_len,
    0,
    FlattenDepth::Finite(1),
    Some((mapper_fn, this_arg)),
  )?;

  Ok(Value::Object(target))
}

/// `Array.prototype.findLast(predicate[, thisArg])` (ECMA-262).
pub fn array_prototype_find_last(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.findlast
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`LengthOfArrayLike` and predicate checks.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let predicate = args.get(0).copied().unwrap_or(Value::Undefined);
  scope.push_root(predicate)?;

  let this_arg = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(this_arg)?;

  // Spec order: `LengthOfArrayLike` is evaluated before `IsCallable(predicate)`.
  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  if !scope.heap().is_callable(predicate)? {
    return Err(VmError::TypeError(
      "Array.prototype.findLast predicate is not callable",
    ));
  }

  let mut k = len;
  while k > 0 {
    k -= 1;
    if k % 1024 == 0 {
      vm.tick()?;
    }

    // Use a nested scope so per-iteration roots do not accumulate.
    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;

    // Unlike `find` / `findIndex`, `findLast` visits indices even when the property is missing
    // (treating holes as `undefined`), so do not guard with `HasProperty`.
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;

    let call_args = [value, Value::Number(k as f64), Value::Object(obj)];
    let selected_val =
      vm.call_with_host_and_hooks(host, &mut iter_scope, hooks, predicate, this_arg, &call_args)?;
    if iter_scope.heap().to_boolean(selected_val)? {
      return Ok(value);
    }
  }

  Ok(Value::Undefined)
}

/// `Array.prototype.findLastIndex(predicate[, thisArg])` (ECMA-262).
pub fn array_prototype_find_last_index(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.findlastindex
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject` / `LengthOfArrayLike` and predicate checks.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let predicate = args.get(0).copied().unwrap_or(Value::Undefined);
  scope.push_root(predicate)?;

  let this_arg = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(this_arg)?;

  // Spec order: `LengthOfArrayLike` is evaluated before `IsCallable(predicate)`.
  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  if !scope.heap().is_callable(predicate)? {
    return Err(VmError::TypeError(
      "Array.prototype.findLastIndex predicate is not callable",
    ));
  }

  let mut k = len;
  while k > 0 {
    k -= 1;
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;

    // Unlike `find` / `findIndex`, `findLastIndex` visits indices even when the property is missing
    // (treating holes as `undefined`), so do not guard with `HasProperty`.
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;

    let call_args = [value, Value::Number(k as f64), Value::Object(obj)];
    let selected_val =
      vm.call_with_host_and_hooks(host, &mut iter_scope, hooks, predicate, this_arg, &call_args)?;
    if iter_scope.heap().to_boolean(selected_val)? {
      return Ok(Value::Number(k as f64));
    }
  }

  Ok(Value::Number(-1.0))
}

/// `Array.prototype.toReversed()` (ES2023).
pub fn array_prototype_to_reversed(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.toreversed
  let mut scope = scope.reborrow();

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let out = array_create_with_intrinsics(vm, &mut scope, len)?;
  scope.push_root(Value::Object(out))?;

  for k in 0..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let from = len
      .checked_sub(k)
      .and_then(|v| v.checked_sub(1))
      .ok_or(VmError::OutOfMemory)?;

    // Use a nested scope so per-iteration roots do not accumulate.
    let mut iter_scope = scope.reborrow();

    let (from_key, from_root) = alloc_array_index_key_from_usize(&mut iter_scope, from)?;
    iter_scope.push_root(from_root)?;

    let (to_key, to_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(to_root)?;

    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, from_key, Value::Object(obj))?;
    iter_scope.push_root(value)?;
    iter_scope.create_data_property_or_throw(out, to_key, value)?;
  }

  Ok(Value::Object(out))
}

/// `Array.prototype.toSorted([compareFn])` (ES2023).
pub fn array_prototype_to_sorted(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.tosorted
  use std::cmp::Ordering;
  const TICK_EVERY: usize = 1024;

  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject` / `IsCallable(compareFn)` checks.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let comparefn = args.get(0).copied().unwrap_or(Value::Undefined);
  if !matches!(comparefn, Value::Undefined) && !scope.heap().is_callable(comparefn)? {
    return Err(VmError::TypeError("Array.prototype.toSorted compareFn is not callable"));
  }
  scope.push_root(comparefn)?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  // `ArrayCreate(len)` can throw a RangeError when `len > 2**32 - 1`.
  //
  // test262 expects this RangeError to be thrown *before* any indexed property lookups occur, so
  // perform the array creation up-front instead of after collecting/sorting values.
  let out = array_create_with_intrinsics(vm, &mut scope, len)?;
  scope.push_root(Value::Object(out))?;

  #[derive(Clone, Copy)]
  struct SortItem {
    value: Value,
    original_pos: usize,
  }

  let mut items: Vec<SortItem> = Vec::new();
  items
    .try_reserve_exact(len.min(1024))
    .map_err(|_| VmError::OutOfMemory)?;

  // Collect values via `Get` (holes are converted to `undefined` / prototype values).
  for k in 0..len {
    if k % TICK_EVERY == 0 {
      vm.tick()?;
    }

    let value = {
      let mut iter_scope = scope.reborrow();
      let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
      iter_scope.push_root(key_root)?;
      iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?
    };

    // Root captured values for the duration of the sort so they remain alive even if user
    // comparator/toString side-effects delete them from the receiver.
    scope.push_root(value)?;
    vec_try_push(
      &mut items,
      SortItem {
        value,
        original_pos: k,
      },
    )?;
  }

  let mut sort_err: Option<VmError> = None;
  let mut compare_count: usize = 0;
  items.sort_unstable_by(|a, b| {
    if sort_err.is_some() {
      return a.original_pos.cmp(&b.original_pos);
    }

    compare_count = compare_count.wrapping_add(1);
    if compare_count % TICK_EVERY == 0 {
      if let Err(e) = vm.tick() {
        sort_err = Some(e);
        return a.original_pos.cmp(&b.original_pos);
      }
    }

    let result: Result<Ordering, VmError> = (|| {
      // Undefined sorts to the end (regardless of comparefn).
      match (a.value, b.value) {
        (Value::Undefined, Value::Undefined) => return Ok(Ordering::Equal),
        (Value::Undefined, _) => return Ok(Ordering::Greater),
        (_, Value::Undefined) => return Ok(Ordering::Less),
        _ => {}
      }

      // User comparefn.
      if !matches!(comparefn, Value::Undefined) {
        let cmp_value = vm.call_with_host_and_hooks(
          host,
          &mut scope,
          hooks,
          comparefn,
          Value::Undefined,
          &[a.value, b.value],
        )?;
        let n = scope.to_number(vm, host, hooks, cmp_value)?;
        if n.is_nan() || n == 0.0 {
          return Ok(Ordering::Equal);
        }
        return Ok(if n < 0.0 { Ordering::Less } else { Ordering::Greater });
      }

      // Default string comparison (UTF-16 code unit order).
      let mut cmp_scope = scope.reborrow();
      cmp_scope.push_roots(&[a.value, b.value])?;

      let a_str = cmp_scope.to_string(vm, host, hooks, a.value)?;
      cmp_scope.push_root(Value::String(a_str))?;
      let b_str = cmp_scope.to_string(vm, host, hooks, b.value)?;
      cmp_scope.push_root(Value::String(b_str))?;

      let a_units = cmp_scope.heap().get_string(a_str)?.as_code_units();
      let b_units = cmp_scope.heap().get_string(b_str)?.as_code_units();
      Ok(a_units.cmp(b_units))
    })();

    let ord = match result {
      Ok(ord) => ord,
      Err(e) => {
        sort_err = Some(e);
        Ordering::Equal
      }
    };

    if ord == Ordering::Equal {
      // Ensure stability by falling back to the original collection order when `SortCompare`
      // produces 0.
      a.original_pos.cmp(&b.original_pos)
    } else {
      ord
    }
  });

  if let Some(err) = sort_err {
    return Err(err);
  }

  for j in 0..len {
    if j % TICK_EVERY == 0 {
      vm.tick()?;
    }

    let value = items[j].value;
    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, j)?;
    iter_scope.push_root(key_root)?;
    iter_scope.create_data_property_or_throw(out, key, value)?;
  }

  Ok(Value::Object(out))
}

/// `Array.prototype.toSpliced(start, deleteCount, ...items)` (ES2023).
pub fn array_prototype_to_spliced(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.tospliced
  let mut scope = scope.reborrow();
  // Root `this` + args before argument coercions and element copying, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  // `Array.prototype.toSpliced` treats a missing `start` argument differently from an explicit
  // `undefined` value: when `start` is not present, `actualDeleteCount` is 0 (copy the array).
  let actual_start = if args.is_empty() {
    0usize
  } else {
    let start_val = args.get(0).copied().unwrap_or(Value::Undefined);
    slice_index_from_value(vm, &mut scope, host, hooks, start_val, len, 0)?
  };

  let insert_count = args.len().saturating_sub(2);

  let actual_delete_count = if args.is_empty() {
    0usize
  } else if args.len() == 1 {
    len.saturating_sub(actual_start)
  } else {
    let delete_count_val = args.get(1).copied().unwrap_or(Value::Undefined);
    let dc = scope.to_integer_or_infinity(vm, host, hooks, delete_count_val)?;
    if dc <= 0.0 {
      0usize
    } else if !dc.is_finite() {
      len.saturating_sub(actual_start)
    } else {
      let max = len.saturating_sub(actual_start);
      (dc as usize).min(max)
    }
  };

  let new_len = len
    .checked_sub(actual_delete_count)
    .and_then(|v| v.checked_add(insert_count))
    .ok_or(VmError::OutOfMemory)?;

  // Per spec, `newLen` is compared against 2**53 - 1 (MAX_SAFE_INTEGER) and throws a TypeError if
  // exceeded, before attempting `ArrayCreate(newLen)` (which would otherwise throw a RangeError due
  // to the 2**32 - 1 array length limit).
  const MAX_SAFE_INTEGER: u64 = (1u64 << 53) - 1;
  if (new_len as u64) > MAX_SAFE_INTEGER {
    return Err(VmError::TypeError("Invalid array length"));
  }

  let out = array_create_with_intrinsics(vm, &mut scope, new_len)?;
  scope.push_root(Value::Object(out))?;

  let mut k = 0usize;

  // Copy prefix (Get-based: holes are converted to `undefined` / prototype values).
  while k < actual_start {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
    iter_scope.push_root(value)?;
    iter_scope.create_data_property_or_throw(out, key, value)?;
    k = k.checked_add(1).ok_or(VmError::OutOfMemory)?;
  }

  // Insert items.
  for item in args.iter().copied().skip(2) {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    iter_scope.push_root(item)?;

    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;
    iter_scope.create_data_property_or_throw(out, key, item)?;
    k = k.checked_add(1).ok_or(VmError::OutOfMemory)?;
  }

  // Copy suffix.
  while k < new_len {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let from = k
      .checked_add(actual_delete_count)
      .and_then(|v| v.checked_sub(insert_count))
      .ok_or(VmError::OutOfMemory)?;

    let mut iter_scope = scope.reborrow();

    let (from_key, from_root) = alloc_array_index_key_from_usize(&mut iter_scope, from)?;
    iter_scope.push_root(from_root)?;

    let (to_key, to_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(to_root)?;

    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, from_key, Value::Object(obj))?;
    iter_scope.push_root(value)?;
    iter_scope.create_data_property_or_throw(out, to_key, value)?;

    k = k.checked_add(1).ok_or(VmError::OutOfMemory)?;
  }

  Ok(Value::Object(out))
}

/// `Array.prototype.with(index, value)` (ES2023).
pub fn array_prototype_with(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-array.prototype.with
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject` / `ToIntegerOrInfinity` and array allocation.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let index_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let relative_index = scope.to_integer_or_infinity(vm, host, hooks, index_val)?;

  if !relative_index.is_finite() {
    return Err(VmError::RangeError("index out of range"));
  }

  let actual_index = if relative_index < 0.0 {
    (len as f64) + relative_index
  } else {
    relative_index
  };

  if actual_index < 0.0 || actual_index >= (len as f64) {
    return Err(VmError::RangeError("index out of range"));
  }

  let actual_index = actual_index as usize;

  let value = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(value)?;

  let out = array_create_with_intrinsics(vm, &mut scope, len)?;
  scope.push_root(Value::Object(out))?;

  for k in 0..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();

    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;

    let from_value = if k == actual_index {
      value
    } else {
      iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?
    };

    iter_scope.push_root(from_value)?;
    iter_scope.create_data_property_or_throw(out, key, from_value)?;
  }

  Ok(Value::Object(out))
}

/// `Array.prototype.map` (minimal).
pub fn array_prototype_map(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`IsCallable(callback)` checks, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let callback = args.get(0).copied().unwrap_or(Value::Undefined);
  if !scope.heap().is_callable(callback)? {
    return Err(VmError::TypeError("Array.prototype.map callback is not callable"));
  }
  scope.push_root(callback)?;

  let this_arg = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(this_arg)?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let intr = require_intrinsics(vm)?;
  let out = scope.alloc_array(len)?;
  scope.push_root(Value::Object(out))?;
  scope
    .heap_mut()
    .object_set_prototype(out, Some(intr.array_prototype()))?;

  for k in 0..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;

    if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      continue;
    }
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;

    // callback(value, index, array)
    let call_args = [value, Value::Number(k as f64), Value::Object(obj)];
    let mapped =
      vm.call_with_host_and_hooks(host, &mut iter_scope, hooks, callback, this_arg, &call_args)?;
    iter_scope.create_data_property_or_throw(out, key, mapped)?;
  }

  Ok(Value::Object(out))
}

/// `Array.prototype.forEach` (ECMA-262) (minimal).
pub fn array_prototype_for_each(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`IsCallable(callback)` checks, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let callback = args.get(0).copied().unwrap_or(Value::Undefined);
  if !scope.heap().is_callable(callback)? {
    return Err(VmError::TypeError("Array.prototype.forEach callback is not callable"));
  }
  scope.push_root(callback)?;

  let this_arg = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(this_arg)?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  for k in 0..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;
    if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      continue;
    }
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;

    let call_args = [value, Value::Number(k as f64), Value::Object(obj)];
    let _ =
      vm.call_with_host_and_hooks(host, &mut iter_scope, hooks, callback, this_arg, &call_args)?;
  }

  Ok(Value::Undefined)
}

/// `Array.prototype.indexOf` (ECMA-262) (minimal).
pub fn array_prototype_index_of(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject` / index coercion, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let search = args.get(0).copied().unwrap_or(Value::Undefined);

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;
  if len == 0 {
    return Ok(Value::Number(-1.0));
  }

  let from_index = args.get(1).copied().unwrap_or(Value::Undefined);
  let start = slice_index_from_value(vm, &mut scope, host, hooks, from_index, len, 0)?;
  if start >= len {
    return Ok(Value::Number(-1.0));
  }

  for k in start..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;
    if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      continue;
    }
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;

    let equal = match (search, value) {
      (Value::Undefined, Value::Undefined) => true,
      (Value::Null, Value::Null) => true,
      (Value::Bool(a), Value::Bool(b)) => a == b,
      (Value::Number(a), Value::Number(b)) => a == b,
      (Value::BigInt(a), Value::BigInt(b)) => a == b,
      (Value::String(a), Value::String(b)) => {
        let a_units = iter_scope.heap().get_string(a)?.as_code_units();
        let b_units = iter_scope.heap().get_string(b)?.as_code_units();
        crate::tick::code_units_eq_with_ticks(a_units, b_units, || vm.tick())?
      }
      (Value::Symbol(a), Value::Symbol(b)) => a == b,
      (Value::Object(a), Value::Object(b)) => a == b,
      _ => false,
    };

    if equal {
      return Ok(Value::Number(k as f64));
    }
  }

  Ok(Value::Number(-1.0))
}

/// `Array.prototype.lastIndexOf` (ECMA-262) (minimal).
pub fn array_prototype_last_index_of(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject` / `ToIntegerOrInfinity` coercions, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  // `ToObject` performs `RequireObjectCoercible` for `null`/`undefined`.
  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let search = args.get(0).copied().unwrap_or(Value::Undefined);

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;
  if len == 0 {
    return Ok(Value::Number(-1.0));
  }

  // Default `fromIndex` is `len - 1`.
  let n = if args.len() > 1 {
    scope.to_integer_or_infinity(vm, host, hooks, args[1])?
  } else {
    (len as f64) - 1.0
  };

  // Determine the starting index `k`.
  let mut k: i64 = if n.is_infinite() {
    if n.is_sign_negative() {
      return Ok(Value::Number(-1.0));
    }
    (len.saturating_sub(1)) as i64
  } else {
    let n_i = n as i64; // saturating float->int cast
    if n_i >= 0 {
      let max = (len.saturating_sub(1)) as i64;
      n_i.min(max)
    } else {
      (len as i64).saturating_add(n_i)
    }
  };

  if k < 0 {
    return Ok(Value::Number(-1.0));
  }

  loop {
    let idx = k as usize;
    if idx % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, idx)?;
    iter_scope.push_root(key_root)?;

    if iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;

      let equal = match (search, value) {
        (Value::Undefined, Value::Undefined) => true,
        (Value::Null, Value::Null) => true,
        (Value::Bool(a), Value::Bool(b)) => a == b,
        (Value::Number(a), Value::Number(b)) => a == b,
        (Value::BigInt(a), Value::BigInt(b)) => a == b,
        (Value::String(a), Value::String(b)) => {
          let a_units = iter_scope.heap().get_string(a)?.as_code_units();
          let b_units = iter_scope.heap().get_string(b)?.as_code_units();
          crate::tick::code_units_eq_with_ticks(a_units, b_units, || vm.tick())?
        }
        (Value::Symbol(a), Value::Symbol(b)) => a == b,
        (Value::Object(a), Value::Object(b)) => a == b,
        _ => false,
      };

      if equal {
        return Ok(Value::Number(idx as f64));
      }
    }

    if k == 0 {
      break;
    }
    k -= 1;
  }

  Ok(Value::Number(-1.0))
}

/// `Array.prototype.includes` (ECMA-262) (minimal).
pub fn array_prototype_includes(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject` / index coercion, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let search = args.get(0).copied().unwrap_or(Value::Undefined);

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;
  if len == 0 {
    return Ok(Value::Bool(false));
  }

  let from_index = args.get(1).copied().unwrap_or(Value::Undefined);
  let start = slice_index_from_value(vm, &mut scope, host, hooks, from_index, len, 0)?;
  if start >= len {
    return Ok(Value::Bool(false));
  }

  for k in start..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }
 
    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;
    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
 
    let equal = match (search, value) {
      (Value::Undefined, Value::Undefined) => true,
      (Value::Null, Value::Null) => true,
      (Value::Bool(a), Value::Bool(b)) => a == b,
      (Value::Number(a), Value::Number(b)) => (a == b) || (a.is_nan() && b.is_nan()),
      (Value::BigInt(a), Value::BigInt(b)) => a == b,
      (Value::String(a), Value::String(b)) => {
        let a_units = iter_scope.heap().get_string(a)?.as_code_units();
        let b_units = iter_scope.heap().get_string(b)?.as_code_units();
        crate::tick::code_units_eq_with_ticks(a_units, b_units, || vm.tick())?
      }
      (Value::Symbol(a), Value::Symbol(b)) => a == b,
      (Value::Object(a), Value::Object(b)) => a == b,
      _ => false,
    };

    if equal {
      return Ok(Value::Bool(true));
    }
  }

  Ok(Value::Bool(false))
}

/// `Array.prototype.filter` (ECMA-262) (minimal).
pub fn array_prototype_filter(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`IsCallable(callback)` checks, which can allocate and GC.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let callback = args.get(0).copied().unwrap_or(Value::Undefined);
  if !scope.heap().is_callable(callback)? {
    return Err(VmError::TypeError("Array.prototype.filter callback is not callable"));
  }
  scope.push_root(callback)?;

  let this_arg = args.get(1).copied().unwrap_or(Value::Undefined);
  scope.push_root(this_arg)?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let intr = require_intrinsics(vm)?;
  let out = scope.alloc_array(0)?;
  scope.push_root(Value::Object(out))?;
  scope
    .heap_mut()
    .object_set_prototype(out, Some(intr.array_prototype()))?;

  let mut to = 0usize;
  for k in 0..len {
    if k % 1024 == 0 {
      vm.tick()?;
    }
 
    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
    iter_scope.push_root(key_root)?;
    if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      continue;
    }

    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
    let call_args = [value, Value::Number(k as f64), Value::Object(obj)];
    let selected_val =
      vm.call_with_host_and_hooks(host, &mut iter_scope, hooks, callback, this_arg, &call_args)?;
    let selected = iter_scope.heap().to_boolean(selected_val)?;
    if !selected {
      continue;
    }

    let (to_key, to_root) = alloc_array_index_key_from_usize(&mut iter_scope, to)?;
    iter_scope.push_root(to_root)?;
    iter_scope.create_data_property_or_throw(out, to_key, value)?;
    to = to.checked_add(1).ok_or(VmError::OutOfMemory)?;
  }

  Ok(Value::Object(out))
}

/// `Array.prototype.reduce` (ECMA-262) (minimal).
pub fn array_prototype_reduce(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`IsCallable(callback)` and accumulator initialization.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let callback = args.get(0).copied().unwrap_or(Value::Undefined);
  if !scope.heap().is_callable(callback)? {
    return Err(VmError::TypeError("Array.prototype.reduce callback is not callable"));
  }
  scope.push_root(callback)?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let intr = require_intrinsics(vm)?;
  let acc_holder = scope.alloc_object()?;
  scope.push_root(Value::Object(acc_holder))?;
  scope
    .heap_mut()
    .object_set_prototype(acc_holder, Some(intr.object_prototype()))?;

  let acc_sym = scope.alloc_symbol(Some("vm-js.internal.ArrayReduceAccumulator"))?;
  scope.push_root(Value::Symbol(acc_sym))?;
  let acc_key = PropertyKey::from_symbol(acc_sym);

  let has_initial = args.len() > 1;
  let mut k = 0usize;
  let mut accumulator: Value;

  if has_initial {
    accumulator = args[1];
  } else {
    // Find the first present element.
    loop {
      if k >= len {
        return Err(VmError::TypeError(
          "Reduce of empty array with no initial value",
        ));
      }
      if k % 1024 == 0 {
        vm.tick()?;
      }

      let mut iter_scope = scope.reborrow();
      let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, k)?;
      iter_scope.push_root(key_root)?;
      if iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
        accumulator =
          iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
        k = k.checked_add(1).ok_or(VmError::OutOfMemory)?;
        break;
      }
      k = k.checked_add(1).ok_or(VmError::OutOfMemory)?;
    }
  }

  // Root the accumulator value by storing it on a rooted helper object. This keeps it live even if
  // the callback returns a freshly allocated object/string and subsequent operations trigger GC.
  scope.define_property(
    acc_holder,
    acc_key,
    data_desc(accumulator, /* writable */ true, /* enumerable */ false, /* configurable */ false),
  )?;

  for idx in k..len {
    if idx % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, idx)?;
    iter_scope.push_root(key_root)?;
    if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      continue;
    }

    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
    let call_args = [accumulator, value, Value::Number(idx as f64), Value::Object(obj)];
    accumulator = vm.call_with_host_and_hooks(
      host,
      &mut iter_scope,
      hooks,
      callback,
      Value::Undefined,
      &call_args,
    )?;

    let ok = iter_scope.ordinary_set_with_host_and_hooks(
      vm,
      host,
      hooks,
      acc_holder,
      acc_key,
      accumulator,
      Value::Object(acc_holder),
    )?;
    if !ok {
      return Err(VmError::TypeError("Array.prototype.reduce failed"));
    }
  }

  Ok(accumulator)
}

/// `Array.prototype.reduceRight` (ECMA-262) (minimal).
pub fn array_prototype_reduce_right(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root `this` + args before `ToObject`/`IsCallable(callback)` and accumulator initialization.
  scope.push_roots_with_extra_roots(args, &[this], &[])?;
  scope.push_root(this)?;

  let obj = scope.to_object(vm, host, hooks, this)?;
  scope.push_root(Value::Object(obj))?;

  let callback = args.get(0).copied().unwrap_or(Value::Undefined);
  if !scope.heap().is_callable(callback)? {
    return Err(VmError::TypeError(
      "Array.prototype.reduceRight callback is not callable",
    ));
  }
  scope.push_root(callback)?;

  let len = length_of_array_like_usize(vm, &mut scope, host, hooks, obj)?;

  let intr = require_intrinsics(vm)?;
  let acc_holder = scope.alloc_object()?;
  scope.push_root(Value::Object(acc_holder))?;
  scope
    .heap_mut()
    .object_set_prototype(acc_holder, Some(intr.object_prototype()))?;

  let acc_sym = scope.alloc_symbol(Some("vm-js.internal.ArrayReduceRightAccumulator"))?;
  scope.push_root(Value::Symbol(acc_sym))?;
  let acc_key = PropertyKey::from_symbol(acc_sym);

  let has_initial = args.len() > 1;
  let mut accumulator: Value;

  // `k` is the next index to process (inclusive) after initializing the accumulator. Use `i64` so
  // we can represent `-1` cleanly.
  let mut k: i64;

  if has_initial {
    accumulator = args[1];
    k = (len as i64) - 1;
  } else {
    // Find the first present element from the right.
    k = (len as i64) - 1;
    loop {
      if k < 0 {
        return Err(VmError::TypeError(
          "Reduce of empty array with no initial value",
        ));
      }

      if (k as usize) % 1024 == 0 {
        vm.tick()?;
      }

      let idx = k as usize;
      let mut iter_scope = scope.reborrow();
      let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, idx)?;
      iter_scope.push_root(key_root)?;
      if iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
        accumulator =
          iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
        k -= 1;
        break;
      }
      k -= 1;
    }
  }

  // Root the accumulator value by storing it on a rooted helper object.
  scope.define_property(
    acc_holder,
    acc_key,
    data_desc(
      accumulator,
      /* writable */ true,
      /* enumerable */ false,
      /* configurable */ false,
    ),
  )?;

  while k >= 0 {
    let idx = k as usize;
    if idx % 1024 == 0 {
      vm.tick()?;
    }

    let mut iter_scope = scope.reborrow();
    let (key, key_root) = alloc_array_index_key_from_usize(&mut iter_scope, idx)?;
    iter_scope.push_root(key_root)?;
    if !iter_scope.has_property_with_host_and_hooks(vm, host, hooks, obj, key)? {
      k -= 1;
      continue;
    }

    let value = iter_scope.get_with_host_and_hooks(vm, host, hooks, obj, key, Value::Object(obj))?;
    let call_args = [
      accumulator,
      value,
      Value::Number(idx as f64),
      Value::Object(obj),
    ];
    accumulator = vm.call_with_host_and_hooks(
      host,
      &mut iter_scope,
      hooks,
      callback,
      Value::Undefined,
      &call_args,
    )?;

    let ok = iter_scope.ordinary_set_with_host_and_hooks(
      vm,
      host,
      hooks,
      acc_holder,
      acc_key,
      accumulator,
      Value::Object(acc_holder),
    )?;
    if !ok {
      return Err(VmError::TypeError("Array.prototype.reduceRight failed"));
    }

    k -= 1;
  }

  Ok(accumulator)
}

