      let rep_units = scope.heap().get_string(rep_s)?.as_code_units();
      vec_try_extend_from_slice(&mut out, rep_units, || vm.tick())?;

      last_end = match_end;

      // Empty needle: advance by one code unit to avoid infinite loops (replacement happens between
