/// `String.prototype.localeCompare` (ECMA-262) (minimal).
///
/// This implementation performs a simple lexicographic comparison of the two UTF-16 code unit
/// sequences. It does **not** implement locale-sensitive collation.
pub fn string_prototype_locale_compare(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let o = crate::spec_ops::require_object_coercible(this)?;

  let that = args.get(0).copied().unwrap_or(Value::Undefined);
  // Root the argument across `ToString(this)` which can invoke user code and trigger GC.
  scope.push_roots(&[o, that])?;

  let a = scope.to_string(vm, host, hooks, o)?;
  scope.push_root(Value::String(a))?;

  let b = scope.to_string(vm, host, hooks, that)?;
  scope.push_root(Value::String(b))?;

  let a_units = { scope.heap().get_string(a)?.as_code_units() };
  let b_units = { scope.heap().get_string(b)?.as_code_units() };

  let min_len = a_units.len().min(b_units.len());
  for i in 0..min_len {
    if i % 1024 == 0 {
      vm.tick()?;
    }
    match a_units[i].cmp(&b_units[i]) {
      core::cmp::Ordering::Less => return Ok(Value::Number(-1.0)),
      core::cmp::Ordering::Greater => return Ok(Value::Number(1.0)),
      core::cmp::Ordering::Equal => {}
    }
  }

  if a_units.len() < b_units.len() {
    Ok(Value::Number(-1.0))
  } else if a_units.len() > b_units.len() {
    Ok(Value::Number(1.0))
  } else {
    Ok(Value::Number(0.0))
  }
}
/// `%String.prototype%[@@iterator]` (ECMA-262).
///
/// This returns an iterator object with internal slots:
/// - `[[IteratedString]]`: stored as a non-enumerable symbol-keyed data property
/// - `[[NextIndex]]`: stored as a non-enumerable symbol-keyed data property
///
/// The iterator object's `next` method is inherited from `%StringIteratorPrototype%`, and the
/// shared native builtin captures the internal slot symbol keys via its own native slots.
pub fn string_prototype_iterator(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  if matches!(this, Value::Null | Value::Undefined) {
    return Err(VmError::TypeError(
      "String.prototype[Symbol.iterator] called on null or undefined",
    ));
  }
  let slots = scope.heap().get_function_native_slots(callee)?;
  if slots.len() != 2 {
    return Err(VmError::InvariantViolation(
      "String.prototype[Symbol.iterator] has wrong native slot count",
    ));
  }
  let Value::Symbol(iterated_sym) = slots[0] else {
    return Err(VmError::InvariantViolation(
      "String.prototype[Symbol.iterator] iteratedString slot is not a symbol",
    ));
  };
  let Value::Symbol(next_index_sym) = slots[1] else {
    return Err(VmError::InvariantViolation(
      "String.prototype[Symbol.iterator] nextIndex slot is not a symbol",
    ));
  };

  let intr = require_intrinsics(vm)?;
  let s = scope.to_string(vm, host, hooks, this)?;
  scope.push_root(Value::String(s))?;

  let iter = scope.alloc_object()?;
  scope.push_root(Value::Object(iter))?;
  scope
    .heap_mut()
    .object_set_prototype(iter, Some(intr.string_iterator_prototype()))?;

  scope.define_property(
    iter,
    PropertyKey::from_symbol(iterated_sym),
    data_desc(Value::String(s), true, false, false),
  )?;
  scope.define_property(
    iter,
    PropertyKey::from_symbol(next_index_sym),
    data_desc(Value::Number(0.0), true, false, false),
  )?;

  Ok(Value::Object(iter))
}

/// `%StringIteratorPrototype%.next` (ECMA-262).
pub fn string_iterator_next(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let intr = require_intrinsics(vm)?;
  let Value::Object(iter) = this else {
    return Err(VmError::TypeError(
      "String iterator next called on non-object",
    ));
  };

  let slots = scope.heap().get_function_native_slots(callee)?;
  if slots.len() != 2 {
    return Err(VmError::InvariantViolation(
      "String iterator next has wrong native slot count",
    ));
  }
  let Value::Symbol(iterated_sym) = slots[0] else {
    return Err(VmError::InvariantViolation(
      "String iterator next iteratedString slot is not a symbol",
    ));
  };
  let Value::Symbol(next_index_sym) = slots[1] else {
    return Err(VmError::InvariantViolation(
      "String iterator next nextIndex slot is not a symbol",
    ));
  };

  if scope.heap().is_proxy_object(iter) {
    return Err(VmError::TypeError(
      "String iterator next called on an object missing internal slots",
    ));
  }

  let iterated_key = PropertyKey::from_symbol(iterated_sym);
  let next_index_key = PropertyKey::from_symbol(next_index_sym);
  let iterated_val = scope
    .heap()
    .object_get_own_data_property_value(iter, &iterated_key)?
    .ok_or(VmError::TypeError(
      "String iterator next called on an object missing internal slots",
    ))?;
  let next_index_val = scope
    .heap()
    .object_get_own_data_property_value(iter, &next_index_key)?
    .ok_or(VmError::TypeError(
      "String iterator next called on an object missing internal slots",
    ))?;

  // Spec: if `[[IteratedString]]` is `undefined`, the iterator is complete.
  let iterated = match iterated_val {
    Value::Undefined => {
      let result = scope.alloc_object()?;
      scope.push_root(Value::Object(result))?;
      scope
        .heap_mut()
        .object_set_prototype(result, Some(intr.object_prototype()))?;
      let value_key = string_key(scope, "value")?;
      scope.define_property(result, value_key, data_desc(Value::Undefined, true, true, true))?;
      let done_key = string_key(scope, "done")?;
      scope.define_property(result, done_key, data_desc(Value::Bool(true), true, true, true))?;
      return Ok(Value::Object(result));
    }
    Value::String(s) => s,
    _ => {
      return Err(VmError::TypeError(
        "String iterator next called on an object missing internal slots",
      ))
    }
  };

  let Value::Number(n) = next_index_val else {
    return Err(VmError::TypeError(
      "String iterator next called on an object missing internal slots",
    ));
  };
  if !n.is_finite() || n < 0.0 || n.fract() != 0.0 || n > usize::MAX as f64 {
    return Err(VmError::TypeError(
      "String iterator next called on an object missing internal slots",
    ));
  }
  let idx = n as usize;

  let len = {
    let string = scope.heap().get_string(iterated)?;
    string.len_code_units()
  };

  // End-of-iteration: clear `[[IteratedString]]` so the underlying string can be collected if this
  // iterator is retained.
  if idx >= len {
    scope.define_property(
      iter,
      iterated_key,
      data_desc(Value::Undefined, true, false, false),
    )?;

    let result = scope.alloc_object()?;
    scope.push_root(Value::Object(result))?;
    scope
      .heap_mut()
      .object_set_prototype(result, Some(intr.object_prototype()))?;
    let value_key = string_key(scope, "value")?;
    scope.define_property(result, value_key, data_desc(Value::Undefined, true, true, true))?;
    let done_key = string_key(scope, "done")?;
    scope.define_property(result, done_key, data_desc(Value::Bool(true), true, true, true))?;
    return Ok(Value::Object(result));
  }

  // Extract the next code point (1-2 UTF-16 code units), per `StringIteratorNext`.
  let (end, units) = {
    let string = scope.heap().get_string(iterated)?;
    let code_units = string.as_code_units();
    let first = code_units
      .get(idx)
      .copied()
      .ok_or(VmError::InvariantViolation(
        "String iterator index out of bounds",
      ))?;
    let mut take = 1usize;
    if (0xD800..=0xDBFF).contains(&first) && idx + 1 < len {
      let second = code_units[idx + 1];
      if (0xDC00..=0xDFFF).contains(&second) {
        take = 2;
      }
    }
    let end = idx + take;
    (end, code_units[idx..end].to_vec())
  };

  // Root the iterator + iterated string while allocating the substring/result object.
  let mut out_scope = scope.reborrow();
  out_scope.push_roots(&[Value::Object(iter), Value::String(iterated)])?;

  let value_s = out_scope.alloc_string_from_u16_vec(units)?;
  out_scope.push_root(Value::String(value_s))?;

  // Advance `[[NextIndex]]`.
  out_scope.define_property(
    iter,
    next_index_key,
    data_desc(Value::Number(end as f64), true, false, false),
  )?;

  // Create `{ value, done: false }`.
  let result = out_scope.alloc_object()?;
  out_scope.push_root(Value::Object(result))?;
  out_scope
    .heap_mut()
    .object_set_prototype(result, Some(intr.object_prototype()))?;
  let value_key = string_key(&mut out_scope, "value")?;
  out_scope.define_property(result, value_key, data_desc(Value::String(value_s), true, true, true))?;
  let done_key = string_key(&mut out_scope, "done")?;
  out_scope.define_property(result, done_key, data_desc(Value::Bool(false), true, true, true))?;

  Ok(Value::Object(result))
}

/// `Number` constructor called as a function.
pub fn number_constructor_call(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let n = match args.first().copied() {
    None => 0.0,
    Some(v) => scope.to_number(vm, host, hooks, v)?,
  };
  Ok(Value::Number(n))
}

/// `new Number(value)` (minimal wrapper object).
pub fn number_constructor_construct(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  args: &[Value],
  new_target: Value,
) -> Result<Value, VmError> {
  let intr = require_intrinsics(vm)?;
  let prim = match args.first().copied() {
    None => 0.0,
    Some(v) => scope.to_number(vm, host, hooks, v)?,
  };

  let proto = crate::spec_ops::get_prototype_from_constructor_with_host_and_hooks(
    vm,
    scope,
    host,
    hooks,
    new_target,
    intr.number_prototype(),
  )?;
  let obj = scope.alloc_object_with_prototype(Some(proto))?;
  scope.push_root(Value::Object(obj))?;

  // Store the primitive value on an internal symbol so `Number.prototype.valueOf` can recover it.
  let marker_sym = scope.heap_mut().ensure_internal_number_data_symbol()?;
  let marker_key = PropertyKey::from_symbol(marker_sym);
  scope.define_property(
    obj,
    marker_key,
    data_desc(Value::Number(prim), true, false, false),
  )?;

  Ok(Value::Object(obj))
}

fn this_number_value(scope: &mut Scope<'_>, this: Value, method: &'static str) -> Result<f64, VmError> {
  match this {
    Value::Number(n) => Ok(n),
    Value::Object(obj) => {
      // Number wrapper internal slots are not present on Proxy objects, even when the Proxy target
      // is a Number wrapper object.
      if scope.heap().is_proxy_object(obj) {
        return Err(VmError::TypeError(method));
      }
      let marker_sym = match scope.heap().internal_number_data_symbol() {
        Some(sym) => sym,
        None => scope.heap_mut().ensure_internal_number_data_symbol()?,
      };
      let marker_key = PropertyKey::from_symbol(marker_sym);
      match scope
        .heap()
        .object_get_own_data_property_value(obj, &marker_key)?
      {
        Some(Value::Number(n)) => Ok(n),
        _ => Err(VmError::TypeError(method)),
      }
    }
    _ => Err(VmError::TypeError(method)),
  }
}

fn this_boolean_value(scope: &mut Scope<'_>, this: Value, method: &'static str) -> Result<bool, VmError> {
  match this {
    Value::Bool(b) => Ok(b),
    Value::Object(obj) => {
      // Boolean wrapper internal slots are not present on Proxy objects, even when the Proxy target
      // is a Boolean wrapper object.
      if scope.heap().is_proxy_object(obj) {
        return Err(VmError::TypeError(method));
      }
      let marker_sym = match scope.heap().internal_boolean_data_symbol() {
        Some(sym) => sym,
        None => scope.heap_mut().ensure_internal_boolean_data_symbol()?,
      };
      let marker_key = PropertyKey::from_symbol(marker_sym);
      match scope
        .heap()
        .object_get_own_data_property_value(obj, &marker_key)?
      {
        Some(Value::Bool(b)) => Ok(b),
        _ => Err(VmError::TypeError(method)),
      }
    }
    _ => Err(VmError::TypeError(method)),
  }
}

#[derive(Clone, Debug)]
struct BigUint {
  // Little-endian base-2^32 limbs.
  limbs: Vec<u32>,
}

impl BigUint {
  fn zero() -> Self {
    Self { limbs: Vec::new() }
  }

  fn try_from_u64(n: u64) -> Result<Self, VmError> {
    if n == 0 {
      return Ok(Self::zero());
    }
    let lo = n as u32;
    let hi = (n >> 32) as u32;
    let mut limbs: Vec<u32> = Vec::new();
    let cap = if hi == 0 { 1usize } else { 2usize };
    limbs.try_reserve_exact(cap).map_err(|_| VmError::OutOfMemory)?;
    limbs.push(lo);
    if hi != 0 {
      limbs.push(hi);
    }
    Ok(Self { limbs })
  }

  fn from_u64(n: u64) -> Self {
    if n == 0 {
      return Self::zero();
    }
    let lo = n as u32;
    let hi = (n >> 32) as u32;
    if hi == 0 {
      Self { limbs: vec![lo] }
    } else {
      Self { limbs: vec![lo, hi] }
    }
  }

  fn is_zero(&self) -> bool {
    self.limbs.is_empty()
  }

  fn normalize(&mut self) {
    while self.limbs.last().is_some_and(|&x| x == 0) {
      self.limbs.pop();
    }
  }

  fn bit_len(&self) -> u32 {
    let Some(&last) = self.limbs.last() else {
      return 0;
    };
    let hi = 32 - last.leading_zeros();
    (self.limbs.len() as u32 - 1) * 32 + hi
  }

  fn bit_is_set(&self, bit: u32) -> bool {
    let word = (bit / 32) as usize;
    let shift = bit % 32;
    let Some(&limb) = self.limbs.get(word) else {
      return false;
    };
    ((limb >> shift) & 1) != 0
  }

  fn shl_bits(&mut self, bits: u32) -> Result<(), VmError> {
    if self.is_zero() || bits == 0 {
      return Ok(());
    }

    let word_shift = (bits / 32) as usize;
    let bit_shift = bits % 32;

    let mut out: Vec<u32> = Vec::new();
    out
      .try_reserve_exact(self.limbs.len().saturating_add(word_shift).saturating_add(1))
      .map_err(|_| VmError::OutOfMemory)?;
    out.extend(std::iter::repeat(0).take(word_shift));
    out.extend_from_slice(&self.limbs);

    if bit_shift != 0 {
      let mut carry: u64 = 0;
      for limb in out.iter_mut() {
        let v = ((*limb as u64) << bit_shift) | carry;
        *limb = v as u32;
        carry = v >> 32;
      }
      if carry != 0 {
        out.push(carry as u32);
      }
    }

    self.limbs = out;
    self.normalize();
    Ok(())
  }

  fn shr_bits(&mut self, bits: u32) {
    if self.is_zero() || bits == 0 {
      return;
    }
    let word_shift = (bits / 32) as usize;
    let bit_shift = bits % 32;
    if word_shift >= self.limbs.len() {
      self.limbs.clear();
      return;
    }
    if word_shift != 0 {
      self.limbs.copy_within(word_shift.., 0);
      self.limbs.truncate(self.limbs.len() - word_shift);
    }

    if bit_shift != 0 {
      let mut carry: u32 = 0;
      for limb in self.limbs.iter_mut().rev() {
        let new_carry = *limb << (32 - bit_shift);
        *limb = (*limb >> bit_shift) | carry;
        carry = new_carry;
      }
    }
    self.normalize();
  }

  fn add_small(&mut self, add: u32) -> Result<(), VmError> {
    if add == 0 {
      return Ok(());
    }
    let mut carry: u64 = add as u64;
    let mut i = 0usize;
    while carry != 0 {
      if i == self.limbs.len() {
        self.limbs.try_reserve_exact(1).map_err(|_| VmError::OutOfMemory)?;
        self.limbs.push(0);
      }
      let sum = self.limbs[i] as u64 + carry;
      self.limbs[i] = sum as u32;
      carry = sum >> 32;
      i = i.saturating_add(1);
    }
    Ok(())
  }

  fn mul_small(&mut self, mul: u32) -> Result<(), VmError> {
    if self.is_zero() || mul == 1 {
      return Ok(());
    }
    if mul == 0 {
      self.limbs.clear();
      return Ok(());
    }

    let mut carry: u64 = 0;
    for limb in self.limbs.iter_mut() {
      let v = (*limb as u64) * (mul as u64) + carry;
      *limb = v as u32;
      carry = v >> 32;
    }
    if carry != 0 {
      self.limbs.try_reserve_exact(1).map_err(|_| VmError::OutOfMemory)?;
      self.limbs.push(carry as u32);
    }
    Ok(())
  }

  fn div_rem_small(&mut self, div: u32) -> Result<u32, VmError> {
    debug_assert!(div != 0);
    if self.is_zero() {
      return Ok(0);
    }

    let mut rem: u64 = 0;
    for limb in self.limbs.iter_mut().rev() {
      let cur = (rem << 32) | (*limb as u64);
      let q = cur / (div as u64);
      rem = cur % (div as u64);
      *limb = q as u32;
    }
    self.normalize();
    Ok(rem as u32)
  }

  fn shr_to_u32(&self, shift: u32) -> u32 {
    if self.is_zero() {
      return 0;
    }
    let word_shift = (shift / 32) as usize;
    let bit_shift = shift % 32;
    if word_shift >= self.limbs.len() {
      return 0;
    }
    let mut v = (self.limbs[word_shift] as u64) >> bit_shift;
    if bit_shift != 0 && word_shift + 1 < self.limbs.len() {
      v |= (self.limbs[word_shift + 1] as u64) << (32 - bit_shift);
    }
    v as u32
  }

  fn truncate_bits(&mut self, bits: u32) {
    if bits == 0 {
      self.limbs.clear();
      return;
    }
    let limbs_len = ((bits + 31) / 32) as usize;
    if self.limbs.len() > limbs_len {
      self.limbs.truncate(limbs_len);
    }
    let rem_bits = bits % 32;
    if rem_bits != 0 {
      if let Some(last) = self.limbs.last_mut() {
        let mask = (1u32 << rem_bits) - 1;
        *last &= mask;
      }
    }
    self.normalize();
  }
}

/// `Number.prototype.valueOf` (minimal).
pub fn number_prototype_value_of(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  Ok(Value::Number(this_number_value(
    scope,
    this,
    "Number.prototype.valueOf called on incompatible receiver",
  )?))
}

fn digit_to_ascii(digit: u32) -> u8 {
  debug_assert!(digit < 36);
  if digit < 10 {
    b'0' + (digit as u8)
  } else {
    b'a' + (digit as u8 - 10)
  }
}

fn number_to_string_radix(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  x: f64,
  radix: u32,
) -> Result<crate::GcString, VmError> {
  debug_assert!(radix >= 2 && radix <= 36);
  debug_assert!(x.is_finite());
  debug_assert!(x != 0.0);

  let x = if x == 0.0 { 0.0 } else { x };
  let negative = x < 0.0;
  let abs = if negative { -x } else { x };

  let bits = abs.to_bits();
  let exp_bits = ((bits >> 52) & 0x7ff) as i32;
  let frac_bits = bits & ((1u64 << 52) - 1);

  // Decompose `abs` into `mantissa * 2^shift` where `mantissa` is an integer and `shift` can be
  // negative. This is an exact representation of the IEEE-754 binary64 value.
  let (mantissa, shift): (u64, i32) = if exp_bits == 0 {
    // subnormal
    (frac_bits, -1074)
  } else {
    let e = exp_bits - 1023;
    ((1u64 << 52) | frac_bits, e - 52)
  };

  // Integer part.
  let mut int = if shift >= 0 {
    let mut v = BigUint::from_u64(mantissa);
    v.shl_bits(shift as u32)?;
    v
  } else {
    let k = (-shift) as u32;
    if k >= 64 {
      BigUint::zero()
    } else {
      BigUint::from_u64(mantissa >> k)
    }
  };

  // Fractional remainder: `rem / 2^denom_bits`.
  let (mut rem, denom_bits): (BigUint, u32) = if shift >= 0 {
    (BigUint::zero(), 0)
  } else {
    let k = (-shift) as u32;
    let r = if k >= 64 {
      mantissa
    } else {
      mantissa & ((1u64 << k) - 1)
    };
    (BigUint::from_u64(r), k)
  };

  // Convert integer part to digits by repeated division.
  let int_bit_len = int.bit_len().max(1);
  let max_int_digits = ((int_bit_len + 1) as usize).min(2048);
  let mut int_digits_rev: Vec<u8> = Vec::new();
  int_digits_rev
    .try_reserve_exact(max_int_digits)
    .map_err(|_| VmError::OutOfMemory)?;

  if int.is_zero() {
    int_digits_rev.push(b'0');
  } else {
    let mut steps = 0usize;
    while !int.is_zero() {
      if steps % 1024 == 0 {
        vm.tick()?;
      }
      let d = int.div_rem_small(radix)? as u32;
      int_digits_rev.push(digit_to_ascii(d));
      steps = steps.saturating_add(1);
      if steps >= 4096 {
        // Hard cap: string outputs should never be unbounded, even for hostile inputs.
        break;
      }
    }
  }

  // Reverse integer digits.
  let mut out: Vec<u16> = Vec::new();

  // Fractional digits will terminate for even radices; for odd radices, cap to keep runtime bounded.
  let max_frac_digits: usize = if denom_bits == 0 {
    0
  } else if radix % 2 == 0 {
    // Each digit in an even radix consumes at least one factor-of-two from the denominator.
    denom_bits as usize
  } else {
    2048
  };

  // Compute conservative output length up-front so we can allocate fallibly once.
  let sign_len = if negative { 1usize } else { 0usize };
  let int_len = int_digits_rev.len();
  let frac_len = if rem.is_zero() { 0usize } else { max_frac_digits.min(2048) };
  let dot_len = if frac_len != 0 { 1usize } else { 0usize };
  let total_len = sign_len
    .saturating_add(int_len)
    .saturating_add(dot_len)
    .saturating_add(frac_len);
  out
    .try_reserve_exact(total_len)
    .map_err(|_| VmError::OutOfMemory)?;

  if negative {
    out.push(b'-' as u16);
  }

  for &b in int_digits_rev.iter().rev() {
    out.push(b as u16);
  }

  if !rem.is_zero() {
    out.push(b'.' as u16);

    let mut digits_written = 0usize;
    while !rem.is_zero() && digits_written < max_frac_digits {
      if digits_written % 1024 == 0 {
        vm.tick()?;
      }

      // rem = rem * radix
      rem.mul_small(radix)?;
      // digit = floor(rem / 2^denom_bits)
      let digit = rem.shr_to_u32(denom_bits);
      // rem = rem mod 2^denom_bits
      rem.truncate_bits(denom_bits);

      out.push(digit_to_ascii(digit) as u16);
      digits_written = digits_written.saturating_add(1);
    }
  }

  scope.alloc_string_from_u16_vec(out)
}

fn add_plus_to_exponent(s: &str) -> Result<String, VmError> {
  let Some((mant, exp)) = s.split_once('e') else {
    let mut out = String::new();
    out.try_reserve_exact(s.len()).map_err(|_| VmError::OutOfMemory)?;
    out.push_str(s);
    return Ok(out);
  };
  let mut out = String::new();
  out
    .try_reserve_exact(mant.len().saturating_add(1).saturating_add(exp.len()).saturating_add(1))
    .map_err(|_| VmError::OutOfMemory)?;
  out.push_str(mant);
  out.push('e');
  if exp.starts_with('-') {
    out.push_str(exp);
  } else {
    out.push('+');
    out.push_str(exp);
  }
  Ok(out)
}

fn parse_ryu_to_decimal<'a>(raw: &str, digits_buf: &'a mut [u8; 32]) -> Result<(&'a [u8], i32), VmError> {
  // `raw` is expected to be ASCII and contain either:
  // - digits with optional decimal point
  // - digits with optional decimal point and a trailing `e[+-]?\d+`
  //
  // Returns `(digits, exp)` such that `value = digits × 10^exp` and `digits` contains no leading
  // zeros.
  let (mantissa, exp_part) = match raw.split_once('e') {
    Some((mantissa, exp)) => (mantissa, Some(exp)),
    None => (raw, None),
  };

  let mut exp: i32 = exp_part.map_or(0, |e| e.parse().unwrap_or(0));

  let mut digits_len = 0usize;
  if let Some((int_part, frac_part)) = mantissa.split_once('.') {
    exp = exp.saturating_sub(frac_part.len() as i32);
    for b in int_part.bytes().chain(frac_part.bytes()) {
      if digits_len >= digits_buf.len() {
        return Err(VmError::InvariantViolation("ryu digit buffer too small"));
      }
      digits_buf[digits_len] = b;
      digits_len += 1;
    }
  } else {
    for b in mantissa.bytes() {
      if digits_len >= digits_buf.len() {
        return Err(VmError::InvariantViolation("ryu digit buffer too small"));
      }
      digits_buf[digits_len] = b;
      digits_len += 1;
    }
  }

  // Strip leading zeros introduced by `0.xxx` forms.
  let mut start = 0usize;
  while start < digits_len && digits_buf[start] == b'0' {
    start += 1;
  }
  if start >= digits_len {
    return Err(VmError::InvariantViolation("expected non-zero number to produce digits"));
  }
  if start > 0 {
    digits_buf.copy_within(start..digits_len, 0);
    digits_len -= start;
  }

  Ok((&digits_buf[..digits_len], exp))
}

fn round_ryu_digits_to_precision(
  digits: &[u8],
  exp: i32,
  precision: usize,
  out_digits: &mut [u8; 128],
) -> Result<i32, VmError> {
  if precision == 0 || precision > out_digits.len() {
    return Err(VmError::InvariantViolation("invalid precision for rounding"));
  }
  if digits.is_empty() {
    return Err(VmError::InvariantViolation("expected non-empty digit slice from ryu"));
  }

  let n = digits.len();
  let mut exp10 = exp
    .checked_add(n as i32)
    .and_then(|v| v.checked_sub(1))
    .ok_or(VmError::InvariantViolation("base-10 exponent overflow in number formatting"))?;

  if n >= precision {
    out_digits[..precision].copy_from_slice(&digits[..precision]);

    if n > precision && digits[precision] >= b'5' {
      // Round half away from zero: any next digit >= 5 increments.
      let mut carry = true;
      for i in (0..precision).rev() {
        if !carry {
          break;
        }
        if out_digits[i] < b'9' {
          out_digits[i] += 1;
          carry = false;
        } else {
          out_digits[i] = b'0';
        }
      }
      if carry {
        out_digits[0] = b'1';
        for d in &mut out_digits[1..precision] {
          *d = b'0';
        }
        exp10 = exp10.saturating_add(1);
      }
    }
  } else {
    out_digits[..n].copy_from_slice(digits);
    for d in &mut out_digits[n..precision] {
      *d = b'0';
    }
  }

  Ok(exp10)
}

/// A `fmt::Write` wrapper that performs fallible `String` growth via `try_reserve`.
///
/// `std::fmt` formatting APIs use infallible `String::push_str`/`push` internally, which can abort
/// the host process on allocator OOM. By routing writes through this wrapper, we can convert
/// allocation failures into `fmt::Error` and surface them as `VmError::OutOfMemory`.
struct FallibleStringWriter<'a> {
  out: &'a mut String,
}

impl Write for FallibleStringWriter<'_> {
  fn write_str(&mut self, s: &str) -> std::fmt::Result {
    self
      .out
      .try_reserve(s.len())
      .map_err(|_| std::fmt::Error)?;
    self.out.push_str(s);
    Ok(())
  }

  fn write_char(&mut self, c: char) -> std::fmt::Result {
    let mut buf = [0u8; 4];
    let encoded = c.encode_utf8(&mut buf);
    self
      .out
      .try_reserve(encoded.len())
      .map_err(|_| std::fmt::Error)?;
    self.out.push(c);
    Ok(())
  }
}

#[inline]
fn try_write_fmt(out: &mut String, args: std::fmt::Arguments<'_>) -> Result<(), VmError> {
  let mut w = FallibleStringWriter { out };
  w.write_fmt(args).map_err(|_| VmError::OutOfMemory)
}

/// `Number.prototype.toString(radix)` (ECMA-262).
pub fn number_prototype_to_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let x = this_number_value(
    &mut scope,
    this,
    "Number.prototype.toString called on incompatible receiver",
  )?;

  let radix_val = args.get(0).copied().unwrap_or(Value::Undefined);
  if matches!(radix_val, Value::Undefined) {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }

  let mut radix = scope.to_number(vm, host, hooks, radix_val)?;
  if radix.is_nan() {
    radix = 0.0;
  }
  if !radix.is_finite() {
    let intr = require_intrinsics(vm)?;
    let err = crate::new_range_error(&mut scope, intr, "Invalid radix")?;
    return Err(VmError::Throw(err));
  }
  radix = radix.trunc();
  if radix < 2.0 || radix > 36.0 {
    let intr = require_intrinsics(vm)?;
    let err = crate::new_range_error(&mut scope, intr, "Invalid radix")?;
    return Err(VmError::Throw(err));
  }
  let radix_u32 = radix as u32;

  if x.is_nan() {
    return Ok(Value::String(scope.alloc_string("NaN")?));
  }
  if x == 0.0 {
    return Ok(Value::String(scope.alloc_string("0")?));
  }
  if x.is_infinite() || radix_u32 == 10 {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }

  let s = number_to_string_radix(vm, &mut scope, x, radix_u32)?;
  Ok(Value::String(s))
}

/// `Number.prototype.toFixed(fractionDigits)` (ECMA-262).
pub fn number_prototype_to_fixed(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let x = this_number_value(
    &mut scope,
    this,
    "Number.prototype.toFixed called on incompatible receiver",
  )?;

  let fd_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let mut f = if matches!(fd_val, Value::Undefined) {
    0.0
  } else {
    scope.to_number(vm, host, hooks, fd_val)?
  };
  if f.is_nan() {
    f = 0.0;
  }
  if !f.is_finite() {
    let intr = require_intrinsics(vm)?;
    let err = crate::new_range_error(&mut scope, intr, "Invalid fractionDigits")?;
    return Err(VmError::Throw(err));
  }
  f = f.trunc();
  if f < 0.0 || f > 100.0 {
    let intr = require_intrinsics(vm)?;
    let err = crate::new_range_error(&mut scope, intr, "Invalid fractionDigits")?;
    return Err(VmError::Throw(err));
  }
  let f = f as usize;

  if x.is_nan() || x.is_infinite() {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }
  if x.abs() >= 1e21 {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }

  // Normalize -0 to +0 so output never includes "-0.00" etc.
  let x = if x == 0.0 { 0.0 } else { x };

  let negative = x < 0.0;
  let abs = if negative { -x } else { x };

  // Implement `toFixed` rounding using exact IEEE-754 decomposition so ties round away from zero
  // (ECMA-262 semantics), rather than Rust's default half-to-even formatting.
  //
  // `abs` is represented as `mantissa * 2^shift` exactly, and we compute:
  //   round(abs * 10^f)
  // as an integer BigUint, rounding half up (ties included).
  let bits = abs.to_bits();
  let exp_bits = ((bits >> 52) & 0x7ff) as i32;
  let frac_bits = bits & ((1u64 << 52) - 1);
  let (mantissa, shift): (u64, i32) = if exp_bits == 0 {
    // subnormal
    (frac_bits, -1074)
  } else {
    let e = exp_bits - 1023;
    ((1u64 << 52) | frac_bits, e - 52)
  };

  let mut scaled = BigUint::try_from_u64(mantissa)?;
  for _ in 0..f {
    scaled.mul_small(10)?;
  }
  if shift >= 0 {
    scaled.shl_bits(shift as u32)?;
  } else {
    let k = (-shift) as u32;
    if k != 0 {
      let round_up = scaled.bit_is_set(k - 1);
      scaled.shr_bits(k);
      if round_up {
        scaled.add_small(1)?;
      }
    }
  }

  // Convert the scaled integer into decimal digits.
  let mut digits_rev: Vec<u8> = Vec::new();
  digits_rev
    .try_reserve_exact(256)
    .map_err(|_| VmError::OutOfMemory)?;
  if scaled.is_zero() {
    digits_rev.push(b'0');
  } else {
    while !scaled.is_zero() {
      let d = scaled.div_rem_small(10)?;
      digits_rev.push(b'0' + (d as u8));
    }
    digits_rev.reverse();
  }

  let digits_len = digits_rev.len();
  let sign_len = if negative { 1usize } else { 0usize };

  let mut buf = String::new();
  if f == 0 {
    let total_len = sign_len.saturating_add(digits_len);
    buf
      .try_reserve_exact(total_len)
      .map_err(|_| VmError::OutOfMemory)?;
    if negative {
      buf.push('-');
    }
    for &b in &digits_rev {
      buf.push(b as char);
    }
  } else {
    let pad_zeros = if digits_len <= f {
      f.saturating_add(1).saturating_sub(digits_len)
    } else {
      0usize
    };
    let total_digits = pad_zeros.saturating_add(digits_len);
    let int_len = total_digits.saturating_sub(f);
    let total_len = sign_len
      .saturating_add(total_digits)
      .saturating_add(1); // '.'
    buf
      .try_reserve_exact(total_len)
      .map_err(|_| VmError::OutOfMemory)?;
    if negative {
      buf.push('-');
    }
    for i in 0..int_len {
      if i < pad_zeros {
        buf.push('0');
      } else {
        buf.push(digits_rev[i - pad_zeros] as char);
      }
    }
    buf.push('.');
    for i in int_len..total_digits {
      if i < pad_zeros {
        buf.push('0');
      } else {
        buf.push(digits_rev[i - pad_zeros] as char);
      }
    }
  }
  let out = scope.alloc_string(&buf)?;
  Ok(Value::String(out))
}

/// `Number.prototype.toExponential(fractionDigits)` (ECMA-262).
pub fn number_prototype_to_exponential(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let x = this_number_value(
    &mut scope,
    this,
    "Number.prototype.toExponential called on incompatible receiver",
  )?;

  if x.is_nan() || x.is_infinite() {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }

  // Normalize -0 to +0 so Rust doesn't emit "-0e0".
  let x = if x == 0.0 { 0.0 } else { x };

  let fd_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let formatted = if matches!(fd_val, Value::Undefined) {
    let mut buf = String::new();
    // `{:e}` uses the shortest round-trippable representation of an f64, which has at most 17
    // significant digits. In `1.xxxxxe±ddd` form, that's at most:
    //   [optional '-'] + 1 digit + '.' + 16 digits + 'e' + [optional '-'] + 3 exponent digits
    let reserve = 1usize + 1 + 1 + 16 + 1 + 1 + 3;
    buf.try_reserve_exact(reserve).map_err(|_| VmError::OutOfMemory)?;
    try_write_fmt(&mut buf, format_args!("{:e}", x))?;
    add_plus_to_exponent(&buf)?
  } else {
    let mut f = scope.to_number(vm, host, hooks, fd_val)?;
    if f.is_nan() {
      f = 0.0;
    }
    if !f.is_finite() {
      let intr = require_intrinsics(vm)?;
      let err = crate::new_range_error(&mut scope, intr, "Invalid fractionDigits")?;
      return Err(VmError::Throw(err));
    }
    f = f.trunc();
    if f < 0.0 || f > 100.0 {
      let intr = require_intrinsics(vm)?;
      let err = crate::new_range_error(&mut scope, intr, "Invalid fractionDigits")?;
      return Err(VmError::Throw(err));
    }
    let f = f as usize;

    let precision = f.saturating_add(1);
    let negative = x < 0.0;
    let abs = if negative { -x } else { x };

    let mut digits_out = [0u8; 128];
    let exp10: i32 = if abs == 0.0 {
      for d in &mut digits_out[..precision] {
        *d = b'0';
      }
      0
    } else {
      let mut ryu_buf = ryu::Buffer::new();
      let raw = ryu_buf.format_finite(abs);
      let mut digits_buf = [0u8; 32];
      let (digits, exp) = parse_ryu_to_decimal(raw, &mut digits_buf)?;
      round_ryu_digits_to_precision(digits, exp, precision, &mut digits_out)?
    };

    let exp_negative = exp10 < 0;
    let exp_abs: u32 = if exp_negative { (-exp10) as u32 } else { exp10 as u32 };
    let mut exp_buf = itoa::Buffer::new();
    let exp_digits = exp_buf.format(exp_abs);

    let sign_len = if negative { 1usize } else { 0usize };
    let mantissa_len = 1usize.saturating_add(if f > 0 { 1usize.saturating_add(f) } else { 0 });
    let total_len = sign_len
      .saturating_add(mantissa_len)
      .saturating_add(1) // 'e'
      .saturating_add(1) // exponent sign
      .saturating_add(exp_digits.len());

    let mut out = String::new();
    out
      .try_reserve_exact(total_len)
      .map_err(|_| VmError::OutOfMemory)?;
    if negative {
      out.push('-');
    }
    out.push(digits_out[0] as char);
    if f > 0 {
      out.push('.');
      for &b in &digits_out[1..precision] {
        out.push(b as char);
      }
    }
    out.push('e');
    out.push(if exp_negative { '-' } else { '+' });
    out.push_str(exp_digits);
    out
  };

  let out = scope.alloc_string(&formatted)?;
  Ok(Value::String(out))
}

/// `Number.prototype.toPrecision(precision)` (ECMA-262).
pub fn number_prototype_to_precision(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let x = this_number_value(
    &mut scope,
    this,
    "Number.prototype.toPrecision called on incompatible receiver",
  )?;

  let precision_val = args.get(0).copied().unwrap_or(Value::Undefined);
  if matches!(precision_val, Value::Undefined) {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }

  let mut p = scope.to_number(vm, host, hooks, precision_val)?;
  if p.is_nan() {
    p = 0.0;
  }
  if !p.is_finite() {
    let intr = require_intrinsics(vm)?;
    let err = crate::new_range_error(&mut scope, intr, "Invalid precision")?;
    return Err(VmError::Throw(err));
  }
  p = p.trunc();
  if p < 1.0 || p > 100.0 {
    let intr = require_intrinsics(vm)?;
    let err = crate::new_range_error(&mut scope, intr, "Invalid precision")?;
    return Err(VmError::Throw(err));
  }
  let p = p as usize;

  if x.is_nan() || x.is_infinite() {
    return Ok(Value::String(scope.heap_mut().to_string(Value::Number(x))?));
  }

  // Normalize -0 to +0.
  let x = if x == 0.0 { 0.0 } else { x };
  let negative = x < 0.0;
  let abs = if negative { -x } else { x };

  let mut digits_out = [0u8; 128];
  let exp10: i32 = if abs == 0.0 {
    for d in &mut digits_out[..p] {
      *d = b'0';
    }
    0
  } else {
    let mut ryu_buf = ryu::Buffer::new();
    let raw = ryu_buf.format_finite(abs);
    let mut digits_buf = [0u8; 32];
    let (digits, exp) = parse_ryu_to_decimal(raw, &mut digits_buf)?;
    round_ryu_digits_to_precision(digits, exp, p, &mut digits_out)?
  };

  let use_exponential = exp10 < -6 || exp10 >= (p as i32);
  let mut out = String::new();

  if use_exponential {
    let exp_negative = exp10 < 0;
    let exp_abs: u32 = if exp_negative { (-exp10) as u32 } else { exp10 as u32 };
    let mut exp_buf = itoa::Buffer::new();
    let exp_digits = exp_buf.format(exp_abs);

    let sign_len = if negative { 1usize } else { 0usize };
    let mantissa_len = if p == 1 { 1usize } else { p.saturating_add(1) };
    let total_len = sign_len
      .saturating_add(mantissa_len)
      .saturating_add(1) // 'e'
      .saturating_add(1) // exponent sign
      .saturating_add(exp_digits.len());
    out.try_reserve_exact(total_len).map_err(|_| VmError::OutOfMemory)?;

    if negative {
      out.push('-');
    }
    out.push(digits_out[0] as char);
    if p > 1 {
      out.push('.');
      for &b in &digits_out[1..p] {
        out.push(b as char);
      }
    }
    out.push('e');
    out.push(if exp_negative { '-' } else { '+' });
    out.push_str(exp_digits);
  } else {
    let decimal_pos: i32 = exp10 + 1;

    let sign_len = if negative { 1usize } else { 0usize };
    if decimal_pos <= 0 {
      let leading_zeros = (-decimal_pos) as usize;
      let total_len = sign_len
        .saturating_add(2) // "0."
        .saturating_add(leading_zeros)
        .saturating_add(p);
      out.try_reserve_exact(total_len).map_err(|_| VmError::OutOfMemory)?;

      if negative {
        out.push('-');
      }
      out.push('0');
      out.push('.');
      for _ in 0..leading_zeros {
        out.push('0');
      }
      for &b in &digits_out[..p] {
        out.push(b as char);
      }
    } else {
      let dec = decimal_pos as usize;
      let dot_len = if dec < p { 1usize } else { 0usize };
      let total_len = sign_len.saturating_add(p).saturating_add(dot_len);
      out.try_reserve_exact(total_len).map_err(|_| VmError::OutOfMemory)?;

      if negative {
        out.push('-');
      }
      for &b in &digits_out[..dec.min(p)] {
        out.push(b as char);
      }
      if dec < p {
        out.push('.');
        for &b in &digits_out[dec..p] {
          out.push(b as char);
        }
      } else {
        // `dec > p` can happen only if `use_exponential` is false and rounding increased the
        // exponent; in that case `dec == p` and the mantissa is an integer.
        for _ in 0..dec.saturating_sub(p) {
          out.push('0');
        }
      }
    }
  }

  let out = scope.alloc_string(&out)?;
  Ok(Value::String(out))
}

/// `Number.prototype.toLocaleString` (placeholder).
pub fn number_prototype_to_locale_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  number_prototype_to_string(vm, scope, host, hooks, callee, this, &[])
}

/// `Boolean` constructor called as a function.
pub fn boolean_constructor_call(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let b = match args.first().copied() {
    None => false,
    Some(v) => scope.heap().to_boolean(v)?,
  };
  Ok(Value::Bool(b))
}

/// `new Boolean(value)` (minimal wrapper object).
pub fn boolean_constructor_construct(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  args: &[Value],
  new_target: Value,
) -> Result<Value, VmError> {
  let intr = require_intrinsics(vm)?;
  let prim = match args.first().copied() {
    None => false,
    Some(v) => scope.heap().to_boolean(v)?,
  };

  let proto = crate::spec_ops::get_prototype_from_constructor_with_host_and_hooks(
    vm,
    scope,
    host,
    hooks,
    new_target,
    intr.boolean_prototype(),
  )?;
  let obj = scope.alloc_object_with_prototype(Some(proto))?;
  scope.push_root(Value::Object(obj))?;

  // Store the primitive value on an internal symbol so `Boolean.prototype.valueOf` can recover it.
  let marker_sym = scope.heap_mut().ensure_internal_boolean_data_symbol()?;
  let marker_key = PropertyKey::from_symbol(marker_sym);
  scope.define_property(
    obj,
    marker_key,
    data_desc(Value::Bool(prim), true, false, false),
  )?;

  Ok(Value::Object(obj))
}

/// `Boolean.prototype.valueOf` (minimal).
pub fn boolean_prototype_value_of(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  Ok(Value::Bool(this_boolean_value(
    scope,
    this,
    "Boolean.prototype.valueOf called on incompatible receiver",
  )?))
}

/// `Boolean.prototype.toString`.
pub fn boolean_prototype_to_string(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let b = this_boolean_value(scope, this, "Boolean.prototype.toString called on incompatible receiver")?;
  if b {
    Ok(Value::String(scope.alloc_string("true")?))
  } else {
    Ok(Value::String(scope.alloc_string("false")?))
  }
}

/// `Boolean.prototype[Symbol.toPrimitive]`.
pub fn boolean_prototype_to_primitive(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let hint = match args.get(0).copied() {
    Some(Value::String(s)) => s,
    _ => return Err(VmError::TypeError("Invalid hint")),
  };

  let units = scope.heap().get_string(hint)?.as_code_units();
  let is_valid_hint = units
    == [
      b'd' as u16,
      b'e' as u16,
      b'f' as u16,
      b'a' as u16,
      b'u' as u16,
      b'l' as u16,
      b't' as u16,
    ] || units
    == [
      b's' as u16,
      b't' as u16,
      b'r' as u16,
      b'i' as u16,
      b'n' as u16,
      b'g' as u16,
    ] || units
    == [
      b'n' as u16,
      b'u' as u16,
      b'm' as u16,
      b'b' as u16,
      b'e' as u16,
      b'r' as u16,
    ];
  if !is_valid_hint {
    return Err(VmError::TypeError("Invalid hint"));
  }

  Ok(Value::Bool(this_boolean_value(
    scope,
    this,
    "Boolean.prototype[Symbol.toPrimitive] called on incompatible receiver",
  )?))
}

/// `Number.isNaN`.
pub fn number_is_nan(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let v = args.get(0).copied().unwrap_or(Value::Undefined);
  match v {
    Value::Number(n) => Ok(Value::Bool(n.is_nan())),
    _ => Ok(Value::Bool(false)),
  }
}

/// `Number.isFinite`.
pub fn number_is_finite(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let v = args.get(0).copied().unwrap_or(Value::Undefined);
  match v {
    Value::Number(n) => Ok(Value::Bool(n.is_finite())),
    _ => Ok(Value::Bool(false)),
  }
}

/// `Number.isInteger`.
pub fn number_is_integer(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let v = args.get(0).copied().unwrap_or(Value::Undefined);
  let Value::Number(n) = v else {
    return Ok(Value::Bool(false));
  };
  if !n.is_finite() {
    return Ok(Value::Bool(false));
  }
  Ok(Value::Bool(n.trunc() == n))
}

/// `Number.isSafeInteger`.
pub fn number_is_safe_integer(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let v = args.get(0).copied().unwrap_or(Value::Undefined);
  let Value::Number(n) = v else {
    return Ok(Value::Bool(false));
  };
  if !n.is_finite() {
    return Ok(Value::Bool(false));
  }
  if n.trunc() != n {
    return Ok(Value::Bool(false));
  }
  Ok(Value::Bool(n.abs() <= 9007199254740991.0))
}

fn this_bigint_value(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  this: Value,
  method: &'static str,
) -> Result<crate::GcBigInt, VmError> {
  match this {
    Value::BigInt(b) => Ok(b),
    Value::Object(obj) => {
      // BigInt wrapper internal slots are not present on Proxy objects, even when the Proxy target
      // is a BigInt wrapper object.
      if scope.heap().is_proxy_object(obj) {
        return Err(VmError::TypeError(method));
      }
      let marker_sym = match scope.heap().internal_bigint_data_symbol() {
        Some(sym) => sym,
        None => scope.heap_mut().ensure_internal_bigint_data_symbol()?,
      };
      let marker_key = PropertyKey::from_symbol(marker_sym);
      match scope
        .heap()
        .object_get_own_data_property_value(obj, &marker_key)?
      {
        Some(Value::BigInt(b)) => Ok(b),
        _ => Err(VmError::TypeError(method)),
      }
    }
    _ => Err(VmError::TypeError(method)),
  }
}

/// ECMAScript `ToBigInt(argument)` (ECMA-262).
fn to_bigint(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  value: Value,
) -> Result<crate::GcBigInt, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-tobigint
  //
  // 1. Let prim be ? ToPrimitive(argument, hint Number).
  // 2. If Type(prim) is BigInt, return prim.
  // 3. If Type(prim) is Boolean, return 1n or 0n.
  // 4. If Type(prim) is String, parse via StringToBigInt; on failure, throw SyntaxError.
  // 5. Otherwise, throw TypeError.
  //
  // `ToBigInt` can invoke user code (via `ToPrimitive`), so root `value` for the duration of the
  // conversion.
  let mut scope = scope.reborrow();
  scope.push_root(value)?;

  let prim = match value {
    Value::Object(_) => scope.to_primitive(vm, host, hooks, value, crate::ToPrimitiveHint::Number)?,
    other => other,
  };
  scope.push_root(prim)?;

  match prim {
    Value::BigInt(b) => Ok(b),
    Value::Bool(true) => scope.alloc_bigint_from_u128(1),
    Value::Bool(false) => scope.alloc_bigint_from_u128(0),
    Value::String(s) => {
      let units = scope.heap().get_string(s)?.as_code_units();
      let parsed = JsBigInt::parse_utf16_string_with_tick(units, &mut || vm.tick())?;
      let Some(bi) = parsed else {
        let err = create_syntax_error(vm, &mut scope, "Cannot convert string to a BigInt")?;
        return Err(VmError::Throw(err));
      };
      scope.alloc_bigint(bi)
    }
    Value::Number(_) => Err(VmError::TypeError("Cannot convert a Number value to a BigInt")),
    Value::Undefined => Err(VmError::TypeError("Cannot convert undefined to a BigInt")),
    Value::Null => Err(VmError::TypeError("Cannot convert null to a BigInt")),
    Value::Symbol(_) => Err(VmError::TypeError("Cannot convert a Symbol value to a BigInt")),
    Value::Object(_) => Err(VmError::InvariantViolation("ToPrimitive returned object")),
  }
}

fn to_index(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  value: Value,
) -> Result<u64, VmError> {
  // ECMA-262 `ToIndex`.
  if matches!(value, Value::Undefined) {
    return Ok(0);
  }

  let n = scope.to_number(vm, host, hooks, value)?;
  let integer = if n.is_nan() { 0.0 } else { n.trunc() };
  if !integer.is_finite() || integer < 0.0 {
    let intr = require_intrinsics(vm)?;
    let err = crate::error_object::new_range_error(scope, intr, "Invalid index")?;
    return Err(VmError::Throw(err));
  }

  const MAX_SAFE_INTEGER: f64 = 9_007_199_254_740_991.0; // 2^53 - 1
  if integer > MAX_SAFE_INTEGER {
    let intr = require_intrinsics(vm)?;
    let err = crate::error_object::new_range_error(scope, intr, "Invalid index")?;
    return Err(VmError::Throw(err));
  }

  Ok(integer as u64)
}

/// `BigInt(value)` (ECMA-262).
pub fn bigint_constructor_call(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-bigint-constructor-number-value
  //
  // 1. If NewTarget is not undefined, throw a TypeError exception. (handled by
  //    `bigint_constructor_construct`)
  // 2. Let prim be ? ToPrimitive(value, hint Number).
  // 3. If Type(prim) is Number, return ? NumberToBigInt(prim).
  // 4. Otherwise, return ? ToBigInt(prim).
  let value = args.get(0).copied().unwrap_or(Value::Undefined);

  // Root `value` across `ToPrimitive`, which can allocate and trigger GC.
  let mut scope = scope.reborrow();
  scope.push_root(value)?;

  let prim = match value {
    Value::Object(_) => scope.to_primitive(vm, host, hooks, value, crate::ToPrimitiveHint::Number)?,
    other => other,
  };
  scope.push_root(prim)?;

  match prim {
    Value::Number(n) => {
      // `NumberToBigInt` throws on NaN/Infinity and non-integers.
      let Some(bi) = JsBigInt::from_f64_exact(n)? else {
        return Err(VmError::RangeError("Cannot convert number to BigInt"));
      };
      let handle = scope.alloc_bigint(bi)?;
      Ok(Value::BigInt(handle))
    }
    other => {
      let bi = to_bigint(vm, &mut scope, host, hooks, other)?;
      Ok(Value::BigInt(bi))
    }
  }
}

/// `new BigInt(...)` (always throws).
pub fn bigint_constructor_construct(
  _vm: &mut Vm,
  _scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _args: &[Value],
  _new_target: Value,
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-bigint-constructor-number-value
  //
  // 1. If NewTarget is not undefined, throw a TypeError exception.
  Err(VmError::TypeError("BigInt is not a constructor"))
}

/// `BigInt.asIntN(bits, bigint)`.
pub fn bigint_as_int_n(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let bits_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let bigint_val = args.get(1).copied().unwrap_or(Value::Undefined);
  let bits = to_index(vm, scope, host, hooks, bits_val)?;
  let bi = to_bigint(vm, scope, host, hooks, bigint_val)?;
  scope.push_root(Value::BigInt(bi))?;

  let out = {
    let bi_ref = scope.heap().get_bigint(bi)?;
    bi_ref.as_int_n(bits)?
  };
  let out = scope.alloc_bigint(out)?;
  Ok(Value::BigInt(out))
}

/// `BigInt.asUintN(bits, bigint)`.
pub fn bigint_as_uint_n(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let bits_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let bigint_val = args.get(1).copied().unwrap_or(Value::Undefined);
  let bits = to_index(vm, scope, host, hooks, bits_val)?;
  let bi = to_bigint(vm, scope, host, hooks, bigint_val)?;
  scope.push_root(Value::BigInt(bi))?;

  let out = {
    let bi_ref = scope.heap().get_bigint(bi)?;
    bi_ref.as_uint_n(bits)?
  };
  let out = scope.alloc_bigint(out)?;
  Ok(Value::BigInt(out))
}

fn bigint_to_string_radix(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  x: crate::GcBigInt,
  radix: u32,
) -> Result<GcString, VmError> {
  debug_assert!((2..=36).contains(&radix));
  let bi = scope.heap().get_bigint(x)?;
  let s = bi.to_string_radix_with_tick(radix, &mut || vm.tick())?;
  scope.alloc_string(&s)
}

/// `BigInt.prototype.valueOf` (ECMA-262).
pub fn bigint_prototype_value_of(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  Ok(Value::BigInt(this_bigint_value(
    vm,
    scope,
    this,
    "BigInt.prototype.valueOf called on incompatible receiver",
  )?))
}

/// `BigInt.prototype.toString` (ECMA-262).
pub fn bigint_prototype_to_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let x = this_bigint_value(
    vm,
    scope,
    this,
    "BigInt.prototype.toString called on incompatible receiver",
  )?;

  let radix_val = args.get(0).copied().unwrap_or(Value::Undefined);
  let radix = if matches!(radix_val, Value::Undefined) {
    10u32
  } else {
    let radix_f = scope.to_integer_or_infinity(vm, host, hooks, radix_val)?;
    if radix_f < 2.0 || radix_f > 36.0 {
      return Err(VmError::RangeError("invalid radix"));
    }
    radix_f as u32
  };

  let s = bigint_to_string_radix(vm, scope, x, radix)?;
  Ok(Value::String(s))
}

/// `BigInt.prototype.toLocaleString` (placeholder).
pub fn bigint_prototype_to_locale_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // Until `Intl` is implemented, behave like most engines when Intl is absent and fall back to
  // `toString()`.
  let x = this_bigint_value(
    vm,
    scope,
    this,
    "BigInt.prototype.toLocaleString called on incompatible receiver",
  )?;
  let s = bigint_to_string_radix(vm, scope, x, 10)?;
  Ok(Value::String(s))
}

/// `Symbol.prototype.valueOf` (minimal).
pub fn symbol_prototype_value_of(
  _vm: &mut Vm,
  scope: &mut Scope<'_>,
  _host: &mut dyn VmHost,
  _hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  match this {
    Value::Symbol(s) => Ok(Value::Symbol(s)),
    Value::Object(obj) => {
      if scope.heap().is_proxy_object(obj) {
        return Err(VmError::TypeError(
          "Symbol.prototype.valueOf called on non-Symbol object",
        ));
      }
      let marker_sym = match scope.heap().internal_symbol_data_symbol() {
        Some(sym) => sym,
        None => scope.heap_mut().ensure_internal_symbol_data_symbol()?,
      };
      let marker_key = PropertyKey::from_symbol(marker_sym);
      match scope
        .heap()
        .object_get_own_data_property_value(obj, &marker_key)?
      {
        Some(Value::Symbol(s)) => Ok(Value::Symbol(s)),
        _ => Err(VmError::TypeError(
          "Symbol.prototype.valueOf called on non-Symbol object",
        )),
      }
    }
    _ => Err(VmError::TypeError(
      "Symbol.prototype.valueOf called on non-symbol",
    )),
  }
}

/// `Symbol.prototype.toString` (minimal).
pub fn symbol_prototype_to_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Symbol(sym) = symbol_prototype_value_of(vm, scope, host, hooks, callee, this, &[])? else {
    // `symbol_prototype_value_of` returning a non-symbol would indicate a bug in our intrinsic
    // marker storage.
    return Err(VmError::InvariantViolation(
      "Symbol.prototype.valueOf returned non-symbol",
    ));
  };

  let s = symbol_descriptive_string(scope, sym, || vm.tick())?;
  Ok(Value::String(s))
}

/// `Symbol.prototype[Symbol.toPrimitive]` (minimal).
pub fn symbol_prototype_to_primitive(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  // The spec ignores the hint and returns the Symbol value.
  symbol_prototype_value_of(vm, scope, host, hooks, callee, this, &[])
}

/// `get Symbol.prototype.description`.
pub fn symbol_prototype_description_get(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  this: Value,
  _args: &[Value],
) -> Result<Value, VmError> {
  let Value::Symbol(sym) = symbol_prototype_value_of(vm, scope, host, hooks, callee, this, &[])? else {
    return Err(VmError::InvariantViolation(
      "Symbol.prototype.valueOf returned non-symbol",
    ));
  };
  let desc = scope.heap().get_symbol_description(sym)?;
  Ok(match desc {
    Some(s) => Value::String(s),
    None => Value::Undefined,
  })
}

/// Global `eval(x)`.
///
/// Note: direct eval is handled by the evaluator (`eval(...)` call expressions); this builtin
/// implements *indirect* eval semantics (ECMA-262 `PerformEval` with `direct = false`).
pub fn global_eval(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let arg0 = args.first().copied().unwrap_or(Value::Undefined);
  let Value::String(source_string) = arg0 else {
    return Ok(arg0);
  };

  // Indirect eval executes in the global environment of the `eval` function's realm.
  let (global_object, global_lexical_env) = {
    let f = scope.heap().get_function(callee)?;
    let global_object = f.realm.ok_or(VmError::Unimplemented("eval missing [[Realm]]"))?;
    let global_lexical_env =
      f.closure_env
        .ok_or(VmError::Unimplemented("eval missing [[Environment]]"))?;
    (global_object, global_lexical_env)
  };

  let mut eval_scope = scope.reborrow();
  eval_scope.push_root(Value::Object(global_object))?;
  eval_scope.push_root(Value::String(source_string))?;
  eval_scope.push_env_root(global_lexical_env)?;

  crate::exec::perform_indirect_eval(
    vm,
    &mut eval_scope,
    host,
    hooks,
    global_object,
    global_lexical_env,
    source_string,
  )
}

/// Global `isNaN(x)` (minimal).
pub fn global_is_nan(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let v = args.first().copied().unwrap_or(Value::Undefined);
  let n = scope.to_number(vm, host, hooks, v)?;
  Ok(Value::Bool(n.is_nan()))
}

/// Global `isFinite(x)` (minimal).
pub fn global_is_finite(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let v = args.first().copied().unwrap_or(Value::Undefined);
  let n = scope.to_number(vm, host, hooks, v)?;
  Ok(Value::Bool(n.is_finite()))
}

fn to_int32(n: f64) -> i32 {
  if !n.is_finite() || n == 0.0 {
    return 0;
  }
  // ECMA-262 `ToInt32`: truncate then compute modulo 2^32.
  let int = n.trunc();
  const TWO_32: f64 = 4_294_967_296.0;
  const TWO_31: f64 = 2_147_483_648.0;

  let mut int = int % TWO_32;
  if int < 0.0 {
    int += TWO_32;
  }
  if int >= TWO_31 {
    (int - TWO_32) as i32
  } else {
    int as i32
  }
}

fn radix_digit_value(unit: u16) -> Option<u8> {
  match unit {
    0x0030..=0x0039 => Some((unit - 0x0030) as u8),
    0x0061..=0x007A => Some((unit - 0x0061 + 10) as u8),
    0x0041..=0x005A => Some((unit - 0x0041 + 10) as u8),
    _ => None,
  }
}

/// Global `parseInt(string, radix)` (ECMA-262).
pub fn global_parse_int(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  // Root all args before `ToString`/`ToNumber` coercions, which can allocate/GC and must not
  // invalidate later arguments when this builtin is invoked directly from the host.
  scope.push_roots(args)?;

  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  let radix_arg = args.get(1).copied().unwrap_or(Value::Undefined);

  // 1. Let inputString be ? ToString(string).
  let input_string = scope.to_string(vm, host, hooks, input)?;
  scope.push_root(Value::String(input_string))?;

  // 6. Let R be ℝ(? ToInt32(radix)).
  //
  // Compute this before borrowing `input_string`'s code units from the heap to avoid holding an
  // immutable heap borrow across `ToNumber`/`ToInt32` (which need mutable access to `scope`).
  let mut r: i32 = if matches!(radix_arg, Value::Undefined) {
    0
  } else {
    let r_num = scope.to_number(vm, host, hooks, radix_arg)?;
    to_int32(r_num)
  };

  // 2. Let S be ! TrimString(inputString, ~start~).
  let units = scope.heap().get_string(input_string)?.as_code_units();
  let mut trim_start = 0usize;
  while trim_start < units.len() && is_trim_whitespace_unit(units[trim_start]) {
    if trim_start % 1024 == 0 {
      vm.tick()?;
    }
    trim_start += 1;
  }

  // Work over `S` by keeping a moving slice offset instead of allocating.
  let mut s_start = trim_start;

  // 3. Let sign be 1.
  // 4. If S is not empty and first code unit is '-', sign = -1.
  let mut sign: i32 = 1;
  if s_start < units.len() && units[s_start] == b'-' as u16 {
    sign = -1;
  }

  // 5. If S is not empty and first code unit is '+' or '-', drop it.
  if s_start < units.len() && (units[s_start] == b'+' as u16 || units[s_start] == b'-' as u16) {
    s_start += 1;
  }

  // 7. Let stripPrefix be true.
  let mut strip_prefix = true;
  // 8. If R ≠ 0...
  if r != 0 {
    if !(2..=36).contains(&r) {
      return Ok(Value::Number(f64::NAN));
    }
    if r != 16 {
      strip_prefix = false;
    }
  } else {
    // 9. Else, set R to 10.
    r = 10;
  }

  // 10. If stripPrefix, and S starts with "0x"/"0X", drop it and set R=16.
  if strip_prefix {
    if s_start + 1 < units.len()
      && units[s_start] == b'0' as u16
      && (units[s_start + 1] == b'x' as u16 || units[s_start + 1] == b'X' as u16)
    {
      s_start += 2;
      r = 16;
    }
  }

  // 11. Find `end`: the first code unit that is not a radix-R digit.
  let radix_u8 = u8::try_from(r).unwrap_or(10);
  let mut end = s_start;
  while end < units.len() {
    if end % 1024 == 0 {
      vm.tick()?;
    }
    let Some(digit) = radix_digit_value(units[end]) else {
      break;
    };
    if digit >= radix_u8 {
      break;
    }
    end += 1;
  }

  // 12. Let Z be the substring of S from 0..end. If empty, return NaN.
  if end == s_start {
    return Ok(Value::Number(f64::NAN));
  }

  // 13. Let mathInt be the integer value represented by Z in radix-R.
  // We accumulate in IEEE-754 f64, matching the spec's implementation-defined approximations.
  let mut math_int: f64 = 0.0;
  let radix_f64 = r as f64;
  for (i, &unit) in units[s_start..end].iter().enumerate() {
    if i % 1024 == 0 {
      vm.tick()?;
    }
    // `units[s_start..end]` was validated above to contain only radix digits, but keep this
    // fallible so malformed inputs can never trigger a panic.
    let digit = match radix_digit_value(unit) {
      Some(d) => d as f64,
      None => {
        return Err(VmError::InvariantViolation(
          "ParseInt digit slice contained non-radix digit",
        ));
      }
    };
    math_int = math_int * radix_f64 + digit;
  }

  // 14. Handle -0.
  if math_int == 0.0 {
    if sign == -1 {
      return Ok(Value::Number(-0.0));
    }
    return Ok(Value::Number(0.0));
  }

  Ok(Value::Number((sign as f64) * math_int))
}

fn is_ascii_digit_unit(unit: u16) -> bool {
  (b'0' as u16..=b'9' as u16).contains(&unit)
}

fn parse_ascii_digits_to_i64_with_limit(
  units: &[u16],
  max: i64,
  tick: &mut impl FnMut() -> Result<(), VmError>,
) -> Result<i64, VmError> {
  let mut v: i64 = 0;
  for (i, &u) in units.iter().enumerate() {
    if i % 1024 == 0 {
      tick()?;
    }
    let d = (u - b'0' as u16) as i64;
    if v > max {
      return Ok(max);
    }
    v = v.saturating_mul(10).saturating_add(d);
    if v > max {
      return Ok(max);
    }
  }
  Ok(v)
}

fn parse_float_from_str_decimal_literal_prefix(
  prefix_units: &[u16],
  mut tick: impl FnMut() -> Result<(), VmError>,
) -> Result<f64, VmError> {
  // `prefix_units` must satisfy `StrDecimalLiteral`.
  //
  // Spec: https://tc39.es/ecma262/#sec-parsefloat-string
  // This implementation avoids allocating a Rust `String` proportional to the prefix length.
  //
  // Approach:
  // - Parse digits/decimal/exponent into (trimmed digits, frac_len, exp_part).
  // - Build a small scientific-notation ASCII buffer from at most MAX_SIG_DIGITS digits.
  // - Use `fast_float` to do the final correct rounding to f64.
  //
  // Note: This intentionally preserves the "prefix" semantics (junk after the literal is ignored),
  // but the numeric conversion may be approximated when there are more than MAX_SIG_DIGITS
  // significant digits (bounded memory).

  const INFINITY_UNITS: [u16; 8] = [73, 110, 102, 105, 110, 105, 116, 121]; // "Infinity"
  const MAX_SIG_DIGITS: usize = 128;
  const MAX_EXP_ABS: i64 = 1_000_000_000;

  let mut i = 0usize;
  let mut sign: i32 = 1;
  if prefix_units.get(0) == Some(&(b'+' as u16)) {
    i += 1;
  } else if prefix_units.get(0) == Some(&(b'-' as u16)) {
    sign = -1;
    i += 1;
  }

  // Infinity.
  if i + INFINITY_UNITS.len() <= prefix_units.len()
    && &prefix_units[i..i + INFINITY_UNITS.len()] == INFINITY_UNITS
  {
    return Ok((sign as f64) * f64::INFINITY);
  }

  // Collect significant digits (trim leading zeros).
  let mut digits: [u8; MAX_SIG_DIGITS] = [0; MAX_SIG_DIGITS];
  let mut digits_len: usize = 0;
  let mut sig_len_total: i64 = 0; // total digits after first non-zero (incl zeros)
  let mut saw_nonzero = false;
  let mut after_decimal = false;
  let mut frac_len: i64 = 0;

  // Parse the significand (digits + optional dot + digits), stopping at exponent.
  while i < prefix_units.len() {
    if i % 1024 == 0 {
      tick()?;
    }
    let u = prefix_units[i];
    if u == b'.' as u16 {
      after_decimal = true;
      i += 1;
      continue;
    }
    if u == b'e' as u16 || u == b'E' as u16 {
      break;
    }
    debug_assert!(is_ascii_digit_unit(u), "invalid StrDecimalLiteral prefix");
    let d = (u - b'0' as u16) as u8;
    if after_decimal {
      frac_len = frac_len.saturating_add(1);
    }
    if !saw_nonzero {
      if d == 0 {
        i += 1;
        continue;
      }
      saw_nonzero = true;
    }
    sig_len_total = sig_len_total.saturating_add(1);
    if digits_len < MAX_SIG_DIGITS {
      digits[digits_len] = d;
      digits_len += 1;
    }
    i += 1;
  }

  if !saw_nonzero {
    // The prefix is some decimal literal representing zero.
    // Preserve -0.
    return Ok(if sign == -1 { -0.0 } else { 0.0 });
  }

  // Parse exponent (if present).
  let mut exp_part: i64 = 0;
  if i < prefix_units.len() && (prefix_units[i] == b'e' as u16 || prefix_units[i] == b'E' as u16) {
    i += 1;
    let mut exp_sign: i32 = 1;
    if prefix_units.get(i) == Some(&(b'+' as u16)) {
      i += 1;
    } else if prefix_units.get(i) == Some(&(b'-' as u16)) {
      exp_sign = -1;
      i += 1;
    }
    // Remaining units are digits (prefix validation guarantees at least one).
    exp_part = parse_ascii_digits_to_i64_with_limit(&prefix_units[i..], MAX_EXP_ABS, &mut tick)?;
    if exp_sign == -1 {
      exp_part = -exp_part;
    }
  }

  // Compute scientific notation exponent: exp_e = (exp_part - frac_len) + sig_len_total - 1.
  let exp_e = exp_part
    .saturating_sub(frac_len)
    .saturating_add(sig_len_total.saturating_sub(1));

  // Build a bounded ASCII buffer: "-d.dddde+NNN".
  let mut buf: [u8; 256] = [0; 256];
  let mut out_len: usize = 0;

  let mut push_byte = |b: u8| -> Result<(), VmError> {
    if out_len >= buf.len() {
      return Err(VmError::OutOfMemory);
    }
    buf[out_len] = b;
    out_len += 1;
    Ok(())
  };

  if sign == -1 {
    push_byte(b'-')?;
  }
  push_byte(b'0' + digits[0])?;
  if digits_len > 1 {
    push_byte(b'.')?;
    for &d in &digits[1..digits_len] {
      push_byte(b'0' + d)?;
    }
  }
  push_byte(b'e')?;

  // Exponent sign.
  let mut exp_abs: i64 = exp_e;
  if exp_abs < 0 {
    push_byte(b'-')?;
    exp_abs = -exp_abs;
  } else {
    push_byte(b'+')?;
  }

  // Write exponent digits without allocating.
  let mut tmp: [u8; 32] = [0; 32];
  let mut tmp_len = 0usize;
  let mut n = exp_abs as u64;
  if n == 0 {
    tmp[0] = b'0';
    tmp_len = 1;
  } else {
    while n > 0 {
      tmp[tmp_len] = b'0' + (n % 10) as u8;
      tmp_len += 1;
      n /= 10;
    }
    tmp[..tmp_len].reverse();
  }
  for &b in &tmp[..tmp_len] {
    push_byte(b)?;
  }

  let s = std::str::from_utf8(&buf[..out_len]).map_err(|_| VmError::InvariantViolation("parseFloat buffer not UTF-8"))?;
  Ok(fast_float::parse(s).unwrap_or(f64::NAN))
}

/// Global `parseFloat(string)` (ECMA-262, budgeted).
pub fn global_parse_float(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let mut scope = scope.reborrow();
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  let s = scope.to_string(vm, host, hooks, input)?;
  scope.push_root(Value::String(s))?;
  let units = scope.heap().get_string(s)?.as_code_units();

  // 1. Trim leading whitespace.
  let mut i = 0usize;
  while i < units.len() && is_trim_whitespace_unit(units[i]) {
    if i % 1024 == 0 {
      vm.tick()?;
    }
    i += 1;
  }
  if i >= units.len() {
    return Ok(Value::Number(f64::NAN));
  }

  // 2. Find the longest prefix satisfying `StrDecimalLiteral`.
  let start = i;
  // Optional sign.
  if units[i] == b'+' as u16 || units[i] == b'-' as u16 {
    i += 1;
  }

  const INFINITY_UNITS: [u16; 8] = [73, 110, 102, 105, 110, 105, 116, 121]; // "Infinity"
  if i + INFINITY_UNITS.len() <= units.len() && &units[i..i + INFINITY_UNITS.len()] == INFINITY_UNITS {
    let end = i + INFINITY_UNITS.len();
    let n = parse_float_from_str_decimal_literal_prefix(&units[start..end], || vm.tick())?;
    return Ok(Value::Number(n));
  }

  let mut j = i;
  let mut saw_digit = false;
  while j < units.len() && is_ascii_digit_unit(units[j]) {
    saw_digit = true;
    j += 1;
    if j % 1024 == 0 {
      vm.tick()?;
    }
  }
  if j < units.len() && units[j] == b'.' as u16 {
    j += 1;
    while j < units.len() && is_ascii_digit_unit(units[j]) {
      saw_digit = true;
      j += 1;
      if j % 1024 == 0 {
        vm.tick()?;
      }
    }
  }
  if !saw_digit {
    return Ok(Value::Number(f64::NAN));
  }

  if j < units.len() && (units[j] == b'e' as u16 || units[j] == b'E' as u16) {
    let exp_pos = j;
    let mut k = j + 1;
    if k < units.len() && (units[k] == b'+' as u16 || units[k] == b'-' as u16) {
      k += 1;
    }
    let mut exp_digit = false;
    while k < units.len() && is_ascii_digit_unit(units[k]) {
      exp_digit = true;
      k += 1;
      if k % 1024 == 0 {
        vm.tick()?;
      }
    }
    if exp_digit {
      j = k;
    } else {
      j = exp_pos;
    }
  }

  // 3. Convert the decimal literal substring to a Number value.
  let prefix = &units[start..j];
  let n = parse_float_from_str_decimal_literal_prefix(prefix, || vm.tick())?;
  Ok(Value::Number(n))
}

fn create_uri_error(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHostHooks,
  message: &str,
) -> Result<Value, VmError> {
  let intr = require_intrinsics(vm)?;
  let ctor = intr.uri_error();

  let msg = scope.alloc_string(message)?;
  scope.push_root(Value::String(msg))?;

  let mut host_state = ();
  error_constructor_construct(
    vm,
    scope,
    &mut host_state,
    host,
    ctor,
    &[Value::String(msg)],
    Value::Object(ctor),
  )
}

fn throw_uri_error(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHostHooks,
  message: &str,
) -> Result<Value, VmError> {
  let err = create_uri_error(vm, scope, host, message)?;
  Err(VmError::Throw(err))
}

fn is_encode_uri_unescaped(unit: u16, extra_unescaped: &[u16]) -> bool {
  // `alwaysUnescaped` is "A-Z a-z 0-9 _" + "-.!~*'()".
  matches!(unit, 0x0041..=0x005A) // A-Z
    || matches!(unit, 0x0061..=0x007A) // a-z
    || matches!(unit, 0x0030..=0x0039) // 0-9
    || unit == 0x005F // '_'
    || matches!(unit, 0x002D | 0x002E | 0x0021 | 0x007E | 0x002A | 0x0027 | 0x0028 | 0x0029)
    || extra_unescaped.contains(&unit)
}

fn utf16_code_point_at(units: &[u16], k: usize) -> (u32, usize, bool) {
  // Returns (code_point, code_unit_count, is_unpaired_surrogate)
  let u = units[k];
  if (0xD800..=0xDBFF).contains(&u) {
    if k + 1 < units.len() {
      let u2 = units[k + 1];
      if (0xDC00..=0xDFFF).contains(&u2) {
        let high = (u - 0xD800) as u32;
        let low = (u2 - 0xDC00) as u32;
        let cp = 0x10000 + ((high << 10) | low);
        return (cp, 2, false);
      }
    }
    return (u as u32, 1, true);
  }
  if (0xDC00..=0xDFFF).contains(&u) {
    return (u as u32, 1, true);
  }
  (u as u32, 1, false)
}

fn utf8_encode_code_point(cp: u32) -> [u8; 4] {
  let mut out = [0u8; 4];
  if cp <= 0x7F {
    out[0] = cp as u8;
  } else if cp <= 0x7FF {
    out[0] = 0xC0 | ((cp >> 6) as u8);
    out[1] = 0x80 | ((cp & 0x3F) as u8);
  } else if cp <= 0xFFFF {
    out[0] = 0xE0 | ((cp >> 12) as u8);
    out[1] = 0x80 | (((cp >> 6) & 0x3F) as u8);
    out[2] = 0x80 | ((cp & 0x3F) as u8);
  } else {
    out[0] = 0xF0 | ((cp >> 18) as u8);
    out[1] = 0x80 | (((cp >> 12) & 0x3F) as u8);
    out[2] = 0x80 | (((cp >> 6) & 0x3F) as u8);
    out[3] = 0x80 | ((cp & 0x3F) as u8);
  }
  out
}

fn percent_encode_byte_to_units(byte: u8, out: &mut Vec<u16>) -> Result<(), VmError> {
  const HEX: &[u8; 16] = b"0123456789ABCDEF";
  out.try_reserve(3).map_err(|_| VmError::OutOfMemory)?;
  out.push(b'%' as u16);
  out.push(HEX[(byte >> 4) as usize] as u16);
  out.push(HEX[(byte & 0x0F) as usize] as u16);
  Ok(())
}

fn encode_uri_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  input: Value,
  extra_unescaped: &[u16],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-encode
  let s = scope.to_string(vm, host, hooks, input)?;
  scope.push_root(Value::String(s))?;
  let units = scope.heap().get_string(s)?.as_code_units();

  let mut out: Vec<u16> = Vec::new();
  // Heuristic: most inputs are predominantly ASCII and do not grow much.
  out
    .try_reserve(units.len().min(1024))
    .map_err(|_| VmError::OutOfMemory)?;

  let mut k = 0usize;
  while k < units.len() {
    if k % 1024 == 0 {
      vm.tick()?;
    }
    let c = units[k];
    if is_encode_uri_unescaped(c, extra_unescaped) {
      out.try_reserve(1).map_err(|_| VmError::OutOfMemory)?;
      out.push(c);
      k += 1;
      continue;
    }

    let (cp, count, is_unpaired) = utf16_code_point_at(units, k);
    if is_unpaired {
      return throw_uri_error(vm, scope, hooks, "URI malformed");
    }
    k += count;

    let bytes = utf8_encode_code_point(cp);
    let byte_len = if cp <= 0x7F { 1 } else if cp <= 0x7FF { 2 } else if cp <= 0xFFFF { 3 } else { 4 };
    for &b in &bytes[..byte_len] {
      percent_encode_byte_to_units(b, &mut out)?;
    }
  }

  let out_s = scope.alloc_string_from_u16_vec(out)?;
  Ok(Value::String(out_s))
}

fn parse_hex_digit(unit: u16) -> Option<u8> {
  match unit {
    0x0030..=0x0039 => Some((unit - 0x0030) as u8),
    0x0061..=0x0066 => Some((unit - 0x0061 + 10) as u8),
    0x0041..=0x0046 => Some((unit - 0x0041 + 10) as u8),
    _ => None,
  }
}

fn parse_hex_octet(units: &[u16], pos: usize) -> Option<u8> {
  let hi = parse_hex_digit(*units.get(pos)?)?;
  let lo = parse_hex_digit(*units.get(pos + 1)?)?;
  Some((hi << 4) | lo)
}

fn decode_uri_string(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  input: Value,
  preserve_escape_set: &[u16],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-decode
  let s = scope.to_string(vm, host, hooks, input)?;
  scope.push_root(Value::String(s))?;
  let units = scope.heap().get_string(s)?.as_code_units();

  let mut out: Vec<u16> = Vec::new();
  out
    .try_reserve_exact(units.len())
    .map_err(|_| VmError::OutOfMemory)?;

  let mut k = 0usize;
  while k < units.len() {
    if k % 1024 == 0 {
      vm.tick()?;
    }
    let c = units[k];
    if c != b'%' as u16 {
      out.push(c);
      k += 1;
      continue;
    }

    // Percent escape.
    if k + 3 > units.len() {
      return throw_uri_error(vm, scope, hooks, "URI malformed");
    }
    let escape = &units[k..k + 3];
    let Some(b0) = parse_hex_octet(units, k + 1) else {
      return throw_uri_error(vm, scope, hooks, "URI malformed");
    };

    let leading_ones = (b0 as u8).leading_ones() as usize;
    if leading_ones == 0 {
      let ascii = b0 as u16;
      if preserve_escape_set.contains(&ascii) {
        out.extend_from_slice(escape);
      } else {
        out.push(ascii);
      }
      k += 3;
      continue;
    }

    if leading_ones == 1 || leading_ones > 4 {
      return throw_uri_error(vm, scope, hooks, "URI malformed");
    }

    // Collect continuation bytes.
    let n = leading_ones;
    let mut octets: [u8; 4] = [0; 4];
    octets[0] = b0;
    let mut idx = k + 3;
    for j in 1..n {
      if idx + 3 > units.len() {
        return throw_uri_error(vm, scope, hooks, "URI malformed");
      }
      if units[idx] != b'%' as u16 {
        return throw_uri_error(vm, scope, hooks, "URI malformed");
      }
      let Some(b) = parse_hex_octet(units, idx + 1) else {
        return throw_uri_error(vm, scope, hooks, "URI malformed");
      };
      octets[j] = b;
      idx += 3;
    }

    // Validate UTF-8 sequence and decode code point.
    let cp: u32 = match n {
      2 => {
        let b1 = octets[1];
        if !(0xC2..=0xDF).contains(&b0) || !(0x80..=0xBF).contains(&b1) {
          return throw_uri_error(vm, scope, hooks, "URI malformed");
        }
        (((b0 & 0x1F) as u32) << 6) | ((b1 & 0x3F) as u32)
      }
      3 => {
        let b1 = octets[1];
        let b2 = octets[2];
        let second_ok = match b0 {
          0xE0 => (0xA0..=0xBF).contains(&b1),
          0xED => (0x80..=0x9F).contains(&b1), // exclude surrogate range
          _ => (0x80..=0xBF).contains(&b1),
        };
        if !(0xE0..=0xEF).contains(&b0) || !second_ok || !(0x80..=0xBF).contains(&b2) {
          return throw_uri_error(vm, scope, hooks, "URI malformed");
        }
        (((b0 & 0x0F) as u32) << 12) | (((b1 & 0x3F) as u32) << 6) | ((b2 & 0x3F) as u32)
      }
      4 => {
        let b1 = octets[1];
        let b2 = octets[2];
        let b3 = octets[3];
        let second_ok = match b0 {
          0xF0 => (0x90..=0xBF).contains(&b1),
          0xF4 => (0x80..=0x8F).contains(&b1),
          _ => (0x80..=0xBF).contains(&b1),
        };
        if !(0xF0..=0xF4).contains(&b0)
          || !second_ok
          || !(0x80..=0xBF).contains(&b2)
          || !(0x80..=0xBF).contains(&b3)
        {
          return throw_uri_error(vm, scope, hooks, "URI malformed");
        }
        (((b0 & 0x07) as u32) << 18)
          | (((b1 & 0x3F) as u32) << 12)
          | (((b2 & 0x3F) as u32) << 6)
          | ((b3 & 0x3F) as u32)
      }
      _ => return throw_uri_error(vm, scope, hooks, "URI malformed"),
    };

    // Reject surrogate code points and out-of-range values.
    if cp > 0x10FFFF || (0xD800..=0xDFFF).contains(&cp) {
      return throw_uri_error(vm, scope, hooks, "URI malformed");
    }

    // UTF16EncodeCodePoint
    if cp <= 0xFFFF {
      out.push(cp as u16);
    } else {
      let cp = cp - 0x10000;
      let high = 0xD800 + ((cp >> 10) as u16);
      let low = 0xDC00 + ((cp & 0x3FF) as u16);
      out.push(high);
      out.push(low);
    }

    k = idx;
  }

  let out_s = scope.alloc_string_from_u16_vec(out)?;
  Ok(Value::String(out_s))
}

/// Global `encodeURI(uri)` (ECMA-262).
pub fn global_encode_uri(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // extraUnescaped = ";/?:@&=+$,#"
  const EXTRA: [u16; 11] = [
    b';' as u16,
    b'/' as u16,
    b'?' as u16,
    b':' as u16,
    b'@' as u16,
    b'&' as u16,
    b'=' as u16,
    b'+' as u16,
    b'$' as u16,
    b',' as u16,
    b'#' as u16,
  ];
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  encode_uri_string(vm, scope, host, hooks, input, &EXTRA)
}

/// Global `encodeURIComponent(uriComponent)` (ECMA-262).
pub fn global_encode_uri_component(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  encode_uri_string(vm, scope, host, hooks, input, &[])
}

/// Global `decodeURI(encodedURI)` (ECMA-262).
pub fn global_decode_uri(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // preserveEscapeSet = ";/?:@&=+$,#"
  const PRESERVE: [u16; 11] = [
    b';' as u16,
    b'/' as u16,
    b'?' as u16,
    b':' as u16,
    b'@' as u16,
    b'&' as u16,
    b'=' as u16,
    b'+' as u16,
    b'$' as u16,
    b',' as u16,
    b'#' as u16,
  ];
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  decode_uri_string(vm, scope, host, hooks, input, &PRESERVE)
}

/// Global `decodeURIComponent(encodedURIComponent)` (ECMA-262).
pub fn global_decode_uri_component(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let input = args.get(0).copied().unwrap_or(Value::Undefined);
  decode_uri_string(vm, scope, host, hooks, input, &[])
}

fn math_unary_number_op(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  args: &[Value],
  f: impl FnOnce(f64) -> f64,
) -> Result<Value, VmError> {
  let v = args.first().copied().unwrap_or(Value::Undefined);
  let n = scope.to_number(vm, host, hooks, v)?;
  Ok(Value::Number(f(n)))
}

fn math_binary_number_op(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  args: &[Value],
  f: impl FnOnce(f64, f64) -> f64,
) -> Result<Value, VmError> {
  let a = args.get(0).copied().unwrap_or(Value::Undefined);
  let b = args.get(1).copied().unwrap_or(Value::Undefined);
  // Root both inputs before coercion: `ToNumber(a)` can allocate/GC and must not invalidate `b`
  // under host calls.
  let mut scope = scope.reborrow();
  scope.push_roots(&[a, b])?;
  let x = scope.to_number(vm, host, hooks, a)?;
  let y = scope.to_number(vm, host, hooks, b)?;
  Ok(Value::Number(f(x, y)))
}

fn to_uint32(n: f64) -> u32 {
  if !n.is_finite() || n == 0.0 {
    return 0;
  }
  // ECMA-262 `ToUint32`: truncate then compute modulo 2^32.
  let int = n.trunc();
  const TWO_32: f64 = 4_294_967_296.0;
  let mut int = int % TWO_32;
  if int < 0.0 {
    int += TWO_32;
  }
  int as u32
}

const MATH_VARIADIC_TICK_EVERY: usize = 32;
const MATH_SUM_PRECISE_TICK_EVERY: u64 = 32;
const MATH_SUM_PRECISE_MAX_COUNT: u64 = (1u64 << 53) - 1;

fn sum_precise_bigint_shr_u64(limbs: &[u32], shift: u64) -> u64 {
  let word_shift = (shift / 32) as usize;
  let bit_shift = (shift % 32) as u32;

  let a0 = limbs.get(word_shift).copied().unwrap_or(0) as u128;
  let a1 = limbs.get(word_shift + 1).copied().unwrap_or(0) as u128;
  let a2 = limbs.get(word_shift + 2).copied().unwrap_or(0) as u128;

  let combined = a0 | (a1 << 32) | (a2 << 64);
  (combined >> bit_shift) as u64
}

fn sum_precise_bigint_test_bit(limbs: &[u32], bit_index: u64) -> bool {
  let limb_index = (bit_index / 32) as usize;
  let bit = (bit_index % 32) as u32;
  limbs
    .get(limb_index)
    .copied()
    .unwrap_or(0)
    .wrapping_shr(bit)
    & 1
    == 1
}

fn sum_precise_bigint_has_low_bits(limbs: &[u32], bit_count: u64) -> bool {
  if bit_count == 0 {
    return false;
  }
  let full_limbs = (bit_count / 32) as usize;
  let rem_bits = (bit_count % 32) as u32;

  for &limb in limbs.iter().take(full_limbs) {
    if limb != 0 {
      return true;
    }
  }

  if rem_bits != 0 {
    if let Some(&limb) = limbs.get(full_limbs) {
      let mask = (1u32 << rem_bits) - 1;
      if limb & mask != 0 {
        return true;
      }
    }
  }

  false
}

/// Converts an exact integer sum of binary64 values, scaled by `2^1074`, into a correctly-rounded
/// binary64 (f64) value.
///
/// Each finite binary64 value is a multiple of `2^-1074`, so the exact real sum of any finite
/// sequence is representable as `S * 2^-1074` for some integer `S`.
fn sum_precise_scaled_bigint_to_f64(sum_scaled: &JsBigInt) -> f64 {
  const EXP: i64 = -1074;

  let sign = sum_scaled.is_negative();
  let mag_bit_len = sum_scaled.bit_len();
  if mag_bit_len == 0 {
    return 0.0;
  }

  let limbs = sum_scaled.limbs();
  let mut e: i64 = (mag_bit_len as i64 - 1) + EXP;

  if e > 1023 {
    return if sign {
      f64::NEG_INFINITY
    } else {
      f64::INFINITY
    };
  }

  if e < -1022 {
    // Subnormal: since the exact sum is a multiple of 2^-1074, it is exactly representable as a
    // subnormal (or 0) when `e < -1022`.
    let mantissa = sum_precise_bigint_shr_u64(limbs, 0);
    let bits = ((sign as u64) << 63) | mantissa;
    return f64::from_bits(bits);
  }

  // Normal.
  let sig: u64;
  if mag_bit_len == 53 {
    sig = sum_precise_bigint_shr_u64(limbs, 0);
  } else {
    let k = mag_bit_len - 53;
    let mut hi = sum_precise_bigint_shr_u64(limbs, k);

    let round_bit = sum_precise_bigint_test_bit(limbs, k - 1);
    let sticky = sum_precise_bigint_has_low_bits(limbs, k - 1);
    if round_bit && (sticky || (hi & 1) == 1) {
      hi = hi.wrapping_add(1);
    }

    if hi == (1u64 << 53) {
      hi >>= 1;
      e += 1;
      if e > 1023 {
        return if sign {
          f64::NEG_INFINITY
        } else {
          f64::INFINITY
        };
      }
    }

    sig = hi;
  }

  let exp_bits = (e + 1023) as u64;
  let frac = sig & ((1u64 << 52) - 1);
  let bits = ((sign as u64) << 63) | (exp_bits << 52) | frac;
  f64::from_bits(bits)
}

fn sum_precise_f64_to_scaled_bigint(n: f64) -> Result<JsBigInt, VmError> {
  debug_assert!(n.is_finite());

  let bits = n.to_bits();
  let sign = (bits >> 63) != 0;
  let exp_bits = ((bits >> 52) & 0x7ff) as i32;
  let frac = bits & ((1u64 << 52) - 1);

  let (mantissa, exp) = if exp_bits == 0 {
    // Subnormal or zero.
    (frac, -1074)
  } else {
    ((1u64 << 52) | frac, exp_bits - 1075)
  };

  // Scale from `mantissa * 2^exp` into an integer multiple of `2^-1074`.
  let shift = (exp + 1074) as u64;
  let mut out = JsBigInt::from_u128(mantissa as u128)?;
  if shift != 0 {
    out = out.shl(shift)?;
  }
  if sign {
    out = out.neg()?;
  }
  Ok(out)
}

