/// `Math.hypot(...args)` (ECMA-262).
pub fn math_hypot(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  // Spec: https://tc39.es/ecma262/#sec-math.hypot
  //
  // Must coerce all arguments (in order) before inspecting them so side effects occur even if an
  // earlier argument becomes ±Infinity/NaN.
  if args.is_empty() {
    return Ok(Value::Number(0.0));
  }

  let mut scope = scope.reborrow();
  scope.push_roots(args)?;

  let mut coerced: Vec<f64> = Vec::new();
  coerced
    .try_reserve_exact(args.len())
    .map_err(|_| VmError::OutOfMemory)?;

  for (i, v) in args.iter().copied().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    let n = scope.to_number(vm, host, hooks, v)?;
    coerced.push(n);
  }

  // Spec: ±Infinity overrides NaN.
  for (i, n) in coerced.iter().copied().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    if n.is_infinite() {
      return Ok(Value::Number(f64::INFINITY));
    }
  }

  let mut only_zero = true;
  for (i, n) in coerced.iter().copied().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    if n.is_nan() {
      return Ok(Value::Number(f64::NAN));
    }
    if n != 0.0 {
      only_zero = false;
    }
  }
  if only_zero {
    return Ok(Value::Number(0.0));
  }

  // Numeric stability: fold pairwise `hypot` across the coerced values.
  let mut acc = 0.0f64;
  for (i, n) in coerced.into_iter().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    acc = acc.hypot(n);
  }
  Ok(Value::Number(acc))
}

/// `Math.imul(a, b)` (ECMA-262).
pub fn math_imul(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let a = args.get(0).copied().unwrap_or(Value::Undefined);
  let b = args.get(1).copied().unwrap_or(Value::Undefined);
  // Root both args before coercion: `ToNumber(a)` can allocate/GC and must not invalidate `b` under
  // host calls.
  let mut scope = scope.reborrow();
  scope.push_roots(&[a, b])?;
  let x = scope.to_number(vm, host, hooks, a)?;
  let y = scope.to_number(vm, host, hooks, b)?;
  let ax = to_uint32(x);
  let by = to_uint32(y);
  let out = ax.wrapping_mul(by) as i32;
  Ok(Value::Number(out as f64))
}

