/// `Math.round(x)` (ECMA-262).
pub fn math_round(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  math_unary_number_op(vm, scope, host, hooks, args, |n| {
    if !n.is_finite() || n == 0.0 {
      return n;
    }
    // Spec: https://tc39.es/ecma262/#sec-math.round
    //
    // Avoid `(n + 0.5).floor()` because the intermediate `n + 0.5` can double-round to an integer
    // in IEEE-754 binary64:
    // - values just below a half-integer boundary (e.g. `0.5 - Number.EPSILON / 4`) can round up
    //   to the next integer.
    // - large odd integers near 2^52 can round up to `n + 1`.
    let t = n.trunc();
    let f = n - t;
    if f >= 0.5 {
      t + 1.0
    } else if f < -0.5 {
      t - 1.0
    } else {
      // Preserve `-0.0` when `n` is negative but rounds to zero: `(-0.5..0.0).trunc() == -0.0`.
      t
    }
  })
}

/// `Math.sumPrecise(items)` (ECMA-262).
pub fn math_sum_precise(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  #[derive(Clone, Copy, Debug, PartialEq, Eq)]
  enum State {
    MinusZero,
    Finite,
    PlusInfinity,
    MinusInfinity,
    NotANumber,
  }

  let mut scope = scope.reborrow();

  let items = args.get(0).copied().unwrap_or(Value::Undefined);
  crate::spec_ops::require_object_coercible(items)?;

  let mut iterator_record = crate::iterator::get_iterator(vm, host, hooks, &mut scope, items)?;
  scope.push_roots(&[iterator_record.iterator, iterator_record.next_method])?;

  let mut state = State::MinusZero;
  // Exact sum of finite numbers, scaled by `2^1074` (so the exact real sum is `sum_scaled *
  // 2^-1074`).
  let mut sum_scaled = JsBigInt::zero();
  let mut count: u64 = 0;

  loop {
    if count % MATH_SUM_PRECISE_TICK_EVERY == 0 {
      vm.tick()?;
    }

    let next = match crate::iterator::iterator_step_value(
      vm,
      host,
      hooks,
      &mut scope,
      &mut iterator_record,
    ) {
      Ok(Some(v)) => v,
      Ok(None) => break,
      Err(err) => return Err(err),
    };

    if count >= MATH_SUM_PRECISE_MAX_COUNT {
      let err = VmError::RangeError("Math.sumPrecise: too many elements");
      return Err(iterator_close_on_error(
        vm,
        &mut scope,
        host,
        hooks,
        &iterator_record,
        err,
      ));
    }

    let n = match next {
      Value::Number(n) => n,
      _ => {
        let err = VmError::TypeError("Math.sumPrecise: iterator value is not a Number");
        return Err(iterator_close_on_error(
          vm,
          &mut scope,
          host,
          hooks,
          &iterator_record,
          err,
        ));
      }
    };

    if state != State::NotANumber {
      if n.is_nan() {
        state = State::NotANumber;
      } else if n == f64::INFINITY {
        if state == State::MinusInfinity {
          state = State::NotANumber;
        } else {
          state = State::PlusInfinity;
        }
      } else if n == f64::NEG_INFINITY {
        if state == State::PlusInfinity {
          state = State::NotANumber;
        } else {
          state = State::MinusInfinity;
        }
      } else if !(n == 0.0 && n.is_sign_negative()) && matches!(state, State::MinusZero | State::Finite)
      {
        state = State::Finite;
        if n != 0.0 {
          let term = sum_precise_f64_to_scaled_bigint(n)?;
          sum_scaled = sum_scaled.add(&term)?;
        }
      }
    }

    count += 1;
  }

  match state {
    State::NotANumber => Ok(Value::Number(f64::NAN)),
    State::PlusInfinity => Ok(Value::Number(f64::INFINITY)),
    State::MinusInfinity => Ok(Value::Number(f64::NEG_INFINITY)),
    State::MinusZero => Ok(Value::Number(-0.0)),
    State::Finite => Ok(Value::Number(sum_precise_scaled_bigint_to_f64(&sum_scaled))),
  }
}

/// `Math.max(...args)` (ECMA-262).
pub fn math_max(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  if args.is_empty() {
    return Ok(Value::Number(f64::NEG_INFINITY));
  }

  let mut scope = scope.reborrow();
  scope.push_roots(args)?;

  // Spec: https://tc39.es/ecma262/#sec-math.max
  // Coerce all arguments before inspecting them.
  let mut coerced: Vec<f64> = Vec::new();
  coerced
    .try_reserve_exact(args.len())
    .map_err(|_| VmError::OutOfMemory)?;
  for (i, v) in args.iter().copied().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    coerced.push(scope.to_number(vm, host, hooks, v)?);
  }

  let mut best = f64::NEG_INFINITY;
  for (i, n) in coerced.into_iter().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    if n.is_nan() {
      return Ok(Value::Number(f64::NAN));
    }

    if n > best {
      best = n;
      continue;
    }
    if n == best && n == 0.0 && best.is_sign_negative() && !n.is_sign_negative() {
      // Spec: if either value is +0, `Math.max` must return +0.
      best = n;
    }
  }
  Ok(Value::Number(best))
}

/// `Math.min(...args)` (ECMA-262).
pub fn math_min(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  if args.is_empty() {
    return Ok(Value::Number(f64::INFINITY));
  }

  let mut scope = scope.reborrow();
  scope.push_roots(args)?;

  // Spec: https://tc39.es/ecma262/#sec-math.min
  // Coerce all arguments before inspecting them.
  let mut coerced: Vec<f64> = Vec::new();
  coerced
    .try_reserve_exact(args.len())
    .map_err(|_| VmError::OutOfMemory)?;
  for (i, v) in args.iter().copied().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    coerced.push(scope.to_number(vm, host, hooks, v)?);
  }

  let mut best = f64::INFINITY;
  for (i, n) in coerced.into_iter().enumerate() {
    if i % MATH_VARIADIC_TICK_EVERY == 0 {
      vm.tick()?;
    }
    if n.is_nan() {
      return Ok(Value::Number(f64::NAN));
    }

    if n < best {
      best = n;
      continue;
    }
    if n == best && n == 0.0 && !best.is_sign_negative() && n.is_sign_negative() {
      // Spec: if either value is -0, `Math.min` must return -0.
      best = n;
    }
  }
  Ok(Value::Number(best))
}

/// `Math.pow(base, exponent)` (ECMA-262).
pub fn math_pow(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  let base = args.get(0).copied().unwrap_or(Value::Undefined);
  let exp = args.get(1).copied().unwrap_or(Value::Undefined);
  // Root both args before coercion: `ToNumber(base)` can allocate/GC and must not invalidate `exp`
  // under host calls.
  let mut scope = scope.reborrow();
  scope.push_roots(&[base, exp])?;
  let x = scope.to_number(vm, host, hooks, base)?;
  let y = scope.to_number(vm, host, hooks, exp)?;
  Ok(Value::Number(crate::ops::number_exponentiate(x, y)))
}

