/// `Math.sign(x)` (ECMA-262).
pub fn math_sign(
  vm: &mut Vm,
  scope: &mut Scope<'_>,
  host: &mut dyn VmHost,
  hooks: &mut dyn VmHostHooks,
  _callee: GcObject,
  _this: Value,
  args: &[Value],
) -> Result<Value, VmError> {
  math_unary_number_op(vm, scope, host, hooks, args, |n| {
    if n.is_nan() {
      return f64::NAN;
    }
    if n == 0.0 {
      // Preserve the sign of zero.
      return n;
    }
    if n.is_sign_negative() {
      -1.0
    } else {
      1.0
    }
  })
}

