#[cfg(test)]
mod string_case_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn string_prototype_case_and_locale_compare_require_object_coercible() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (function () {
          function throwsTypeError(thunk) {
            try {
              thunk();
              return false;
            } catch (e) {
              return e instanceof TypeError;
            }
          }

          return (
            throwsTypeError(function () { String.prototype.toLowerCase.call(null); }) &&
            throwsTypeError(function () { String.prototype.toLowerCase.call(undefined); }) &&
            throwsTypeError(function () { String.prototype.toUpperCase.call(null); }) &&
            throwsTypeError(function () { String.prototype.toUpperCase.call(undefined); }) &&
            throwsTypeError(function () { String.prototype.toLocaleLowerCase.call(null); }) &&
            throwsTypeError(function () { String.prototype.toLocaleUpperCase.call(undefined); }) &&
            throwsTypeError(function () { String.prototype.localeCompare.call(null, "a"); }) &&

            "A".toLowerCase() === "a" &&
            "a".toUpperCase() === "A" &&
            // Locale argument should be ignored without Intl support.
            "a".toLocaleUpperCase("tr") === "A" &&

            "a".localeCompare("a") === 0 &&
            "a".localeCompare("b") < 0 &&
            "b".localeCompare("a") > 0
          );
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
}

#[cfg(test)]
mod regexp_unicode_sets_tests {
  use crate::property::PropertyKind;
  use crate::{GcObject, Heap, HeapLimits, JsRuntime, PropertyKey, Realm, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn regexp_prototype_unicode_sets_descriptor_and_this_semantics() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (function () {
          const desc = Object.getOwnPropertyDescriptor(RegExp.prototype, "unicodeSets");
          if (typeof desc !== "object" || desc === null) return false;
          if (desc.enumerable !== false) return false;
          if (desc.configurable !== true) return false;
          if (typeof desc.get !== "function") return false;
          if (desc.set !== undefined) return false;
          if (desc.get.name !== "get unicodeSets") return false;
          if (desc.get.length !== 0) return false;

          if (RegExp.prototype.unicodeSets !== undefined) return false;
          if (/./.unicodeSets !== false) return false;

          let threw = false;
          try {
            Reflect.apply(desc.get, {}, []);
          } catch (e) {
            threw = e && e.name === "TypeError";
          }
          if (!threw) return false;

          threw = false;
          try {
            Reflect.apply(desc.get, "x", []);
          } catch (e) {
            threw = e && e.name === "TypeError";
          }
          if (!threw) return false;

          return true;
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  fn regexp_prototype_getter(
    heap: &Heap,
    regexp_prototype: GcObject,
    name: &str,
  ) -> Result<GcObject, VmError> {
    let keys = heap.own_property_keys(regexp_prototype)?;
    for key in keys {
      let PropertyKey::String(s) = key else {
        continue;
      };
      if heap.get_string(s)?.to_utf8_lossy() != name {
        continue;
      }
      let Some(desc) = heap.object_get_own_property(regexp_prototype, &key)? else {
        continue;
      };
      let PropertyKind::Accessor { get, .. } = desc.kind else {
        return Err(VmError::InvariantViolation(
          "RegExp.prototype getter is not an accessor property",
        ));
      };
      let Value::Object(getter) = get else {
        return Err(VmError::InvariantViolation(
          "RegExp.prototype getter is not a function object",
        ));
      };
      return Ok(getter);
    }
    Err(VmError::InvariantViolation(
      "RegExp.prototype getter not found",
    ))
  }

  #[test]
  fn regexp_prototype_unicode_sets_cross_realm_uses_getter_realm() -> Result<(), VmError> {
    let mut vm = Vm::new(VmOptions::default());
    let mut heap = Heap::new(HeapLimits::new(2 * 1024 * 1024, 2 * 1024 * 1024));

    // Create two realms on the same heap; this mimics `$262.createRealm()` by sharing a symbol
    // registry but requiring builtins to remain realm-correct.
    let mut realm_a = Realm::new(&mut vm, &mut heap).unwrap();
    let intr_a = *realm_a.intrinsics();
    let getter_a = regexp_prototype_getter(&heap, intr_a.regexp_prototype(), "unicodeSets").unwrap();

    let mut realm_b = Realm::new(&mut vm, &mut heap).unwrap();
    let intr_b = *realm_b.intrinsics();
    let getter_b = regexp_prototype_getter(&heap, intr_b.regexp_prototype(), "unicodeSets").unwrap();

    // Same-realm receiver: returns undefined.
    {
      let mut scope = heap.scope();
      let v = vm.call_without_host(
        &mut scope,
        Value::Object(getter_a),
        Value::Object(intr_a.regexp_prototype()),
        &[],
      ).unwrap();
      assert_eq!(v, Value::Undefined);
    }

    // Cross-realm receiver: throws a TypeError from the getter's realm (prototype check).
    {
      let mut scope = heap.scope();
      let err = vm.call_without_host(
        &mut scope,
        Value::Object(getter_a),
        Value::Object(intr_b.regexp_prototype()),
        &[],
      );
      let VmError::ThrowWithStack { value, .. } = err.unwrap_err() else {
        panic!("expected cross-realm unicodeSets getter call to throw");
      };
      let Value::Object(err_obj) = value else {
        panic!("thrown value is not an object");
      };
      assert_eq!(
        scope.heap().object_prototype(err_obj).unwrap(),
        Some(intr_a.type_error_prototype())
      );
    }

    // Reverse direction: other realm getter throws other realm TypeError.
    {
      let mut scope = heap.scope();
      let err = vm.call_without_host(
        &mut scope,
        Value::Object(getter_b),
        Value::Object(intr_a.regexp_prototype()),
        &[],
      );
      let VmError::ThrowWithStack { value, .. } = err.unwrap_err() else {
        panic!("expected cross-realm unicodeSets getter call to throw");
      };
      let Value::Object(err_obj) = value else {
        panic!("thrown value is not an object");
      };
      assert_eq!(
        scope.heap().object_prototype(err_obj).unwrap(),
        Some(intr_b.type_error_prototype())
      );
    }

    realm_a.teardown(&mut heap);
    realm_b.teardown(&mut heap);
    Ok(())
  }

  #[test]
  fn regexp_v_advances_by_code_points_for_empty_global_matches() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(r#"("\u{20BB7}a".match(/(?:)/gv).length === 3)"#)?;
    assert_eq!(v, Value::Bool(true), "match(/(?:)/gv) must advance by code points");

    let v = rt.exec_script(
      r#"
        (function () {
          const s = "\u{20BB7}a";
          let count = 0;
          for (const _ of s.matchAll(/(?:)/gv)) count++;
          return count === 3;
        })()
      "#,
    )?;
    assert_eq!(
      v,
      Value::Bool(true),
      "matchAll(/(?:)/gv) must advance by code points on empty matches"
    );

    let v = rt.exec_script(r#"("\u{20BB7}a".replace(/(?:)/gv, "-") === "-\u{20BB7}-a-")"#)?;
    assert_eq!(
      v,
      Value::Bool(true),
      "replace(/(?:)/gv) must not split surrogate pairs on empty matches"
    );

    let v = rt.exec_script(
      r#"
        (function () {
          const parts = "\u{20BB7}a".split(/(?:)/v);
          return parts.length === 2 && parts[0] === "\u{20BB7}" && parts[1] === "a";
        })()
      "#,
    )?;
    assert_eq!(
      v,
      Value::Bool(true),
      "split(/(?:)/v) must not split surrogate pairs on empty matches"
    );
    Ok(())
  }

  #[test]
  fn regexp_prototype_source_cross_realm_uses_getter_realm() -> Result<(), VmError> {
    let mut vm = Vm::new(VmOptions::default());
    let mut heap = Heap::new(HeapLimits::new(2 * 1024 * 1024, 2 * 1024 * 1024));

    let mut realm_a = Realm::new(&mut vm, &mut heap).unwrap();
    let intr_a = *realm_a.intrinsics();
    let getter_a = regexp_prototype_getter(&heap, intr_a.regexp_prototype(), "source").unwrap();

    let mut realm_b = Realm::new(&mut vm, &mut heap).unwrap();
    let intr_b = *realm_b.intrinsics();
    let getter_b = regexp_prototype_getter(&heap, intr_b.regexp_prototype(), "source").unwrap();

    // Same-realm receiver: returns "(?:)".
    {
      let mut scope = heap.scope();
      let v = vm
        .call_without_host(
          &mut scope,
          Value::Object(getter_a),
          Value::Object(intr_a.regexp_prototype()),
          &[],
        )
        .unwrap();
      let Value::String(s) = v else {
        panic!("expected RegExp.prototype.source on %RegExp.prototype% to return a string");
      };
      assert_eq!(scope.heap().get_string(s).unwrap().to_utf8_lossy(), "(?:)");
    }

    // Cross-realm receiver: throws a TypeError from the getter's realm (prototype check).
    {
      let mut scope = heap.scope();
      let err = vm.call_without_host(
        &mut scope,
        Value::Object(getter_a),
        Value::Object(intr_b.regexp_prototype()),
        &[],
      );
      let VmError::ThrowWithStack { value, .. } = err.unwrap_err() else {
        panic!("expected cross-realm source getter call to throw");
      };
      let Value::Object(err_obj) = value else {
        panic!("thrown value is not an object");
      };
      assert_eq!(
        scope.heap().object_prototype(err_obj).unwrap(),
        Some(intr_a.type_error_prototype())
      );
    }

    // Reverse direction: other realm getter throws other realm TypeError.
    {
      let mut scope = heap.scope();
      let err = vm.call_without_host(
        &mut scope,
        Value::Object(getter_b),
        Value::Object(intr_a.regexp_prototype()),
        &[],
      );
      let VmError::ThrowWithStack { value, .. } = err.unwrap_err() else {
        panic!("expected cross-realm source getter call to throw");
      };
      let Value::Object(err_obj) = value else {
        panic!("thrown value is not an object");
      };
      assert_eq!(
        scope.heap().object_prototype(err_obj).unwrap(),
        Some(intr_b.type_error_prototype())
      );
    }

    realm_a.teardown(&mut heap);
    realm_b.teardown(&mut heap);
    Ok(())
  }
}

#[cfg(test)]
mod proxy_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn proxy_constructor_is_not_callable() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        let threw = false;
        try { Proxy({}, {}); } catch (e) { threw = true; }
        threw
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn proxy_revocable_returns_proxy_and_revoke() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const r = Proxy.revocable({}, {});
        typeof r.proxy === "object" && typeof r.revoke === "function"
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn proxy_revocable_revoke_revokes_proxy() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const r = Proxy.revocable({}, {});
        r.revoke();
        let threw = false;
        try { Reflect.ownKeys(r.proxy); } catch (e) { threw = true; }
        threw
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
}

#[cfg(test)]
mod string_replace_all_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn replace_all_calls_symbol_replace_before_tostring() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const log = [];
        const o = {
          toString() {
            log.push("this");
            throw new Error("ToString(this) should not be called before @@replace");
          }
        };
        const replaceValue = {
          toString() {
            log.push("replace");
            throw new Error("ToString(replaceValue) should not be called before @@replace");
          }
        };
        const searchValue = {
          [Symbol.replace](str, repl) {
            log.push("@@replace");
            return "ok";
          }
        };
        const result = String.prototype.replaceAll.call(o, searchValue, replaceValue);
        result === "ok" && log.join(",") === "@@replace"
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn replace_all_non_global_regexp_throws_before_tostring() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        let threw = false;
        try {
          String.prototype.replaceAll.call(
            { toString() { throw "thisToString"; } },
            /a/,
            { toString() { throw "replaceToString"; } }
          );
        } catch (e) {
          threw = e instanceof TypeError;
        }
        threw
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn replace_all_string_replace_value_and_substitutions() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        "aba".replaceAll("a", "x") === "xbx" &&
        "abc".replaceAll("", "-") === "-a-b-c-" &&
        "aba".replaceAll("a", "$&$&") === "aabaa"
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
}

#[cfg(test)]
mod regexp_prototype_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn regexp_flag_getters_basic() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (/a/d).hasIndices === true &&
        (/a/).hasIndices === false &&
        (/a/g).global === true &&
        (/a/).global === false &&
        (/a/i).ignoreCase === true &&
        (/a/).ignoreCase === false &&
        (/a/m).multiline === true &&
        (/a/).multiline === false &&
        (/a/s).dotAll === true &&
        (/a/).dotAll === false &&
        (/a/u).unicode === true &&
        (/a/).unicode === false &&
        (/a/v).unicodeSets === true &&
        (/a/).unicodeSets === false &&
        (/a/y).sticky === true &&
        (/a/).sticky === false
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_flag_getters_incompatible_receivers() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        // All of the flag getters should return `undefined` when invoked on RegExp.prototype.
        RegExp.prototype.hasIndices === undefined &&
        RegExp.prototype.global === undefined &&
        RegExp.prototype.ignoreCase === undefined &&
        RegExp.prototype.multiline === undefined &&
        RegExp.prototype.dotAll === undefined &&
        RegExp.prototype.unicode === undefined &&
        RegExp.prototype.unicodeSets === undefined &&
        RegExp.prototype.sticky === undefined &&

        // But they should throw TypeError for non-RegExp objects.
        (function() {
          var obj = Object.create(RegExp.prototype);
          var keys = ["hasIndices", "global", "ignoreCase", "multiline", "dotAll", "unicode", "unicodeSets", "sticky"];
          for (var i = 0; i < keys.length; i++) {
            try {
              // Getter is found on RegExp.prototype and invoked with `this = obj`.
              void obj[keys[i]];
              return false;
            } catch (e) {
              if (!(e instanceof TypeError)) return false;
            }
          }
          return true;
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_match_indices_basic() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        // Basic indices array shape + values.
        (function() {
          var m = /b(c)/d.exec("abcd");
          return (
            Array.isArray(m.indices) &&
            m.indices.length === 2 &&
            m.indices[0][0] === 1 && m.indices[0][1] === 3 &&
            m.indices[1][0] === 2 && m.indices[1][1] === 3 &&
            // `groups` is always present on the indices array.
            ("groups" in m.indices) && m.indices.groups === undefined &&
            // `indices` and `indices.groups` are enumerable (CreateDataProperty).
            m.propertyIsEnumerable("indices") === true &&
            Object.prototype.propertyIsEnumerable.call(m.indices, "groups") === true
          );
        })() &&

        // Named capture groups map to the same index-pair array objects.
        (function() {
          var m = /(?<x>b)(c)/d.exec("abc");
          return (
            Object.getPrototypeOf(m.indices.groups) === null &&
            Array.isArray(m.indices.groups.x) &&
            m.indices.groups.x[0] === 1 && m.indices.groups.x[1] === 2 &&
            m.indices.groups.x === m.indices[1]
          );
        })() &&

        // Unmatched groups produce `undefined` entries.
        (function() {
          var m = /(a)?b/d.exec("b");
          return m.indices.length === 2 && m.indices[1] === undefined && ("1" in m.indices);
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_to_string_basic() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        // `flags` are canonicalized (gimsuvy ordering), even if the literal used a different order.
        String(/a/ig) === "/a/gi" &&
        /a/ig.toString() === "/a/gi" &&

        // Generic receiver + observable Get(source)/Get(flags).
        (function() {
          var log = "";
          var obj = {
            get source() { log += "s"; return "a"; },
            get flags() { log += "f"; return "g"; },
          };
          return RegExp.prototype.toString.call(obj) === "/a/g" && log === "sf";
        })() &&

        // Non-object receivers throw TypeError.
        (function() {
          try {
            RegExp.prototype.toString.call(1);
            return false;
          } catch (e) {
            return e instanceof TypeError;
          }
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
  #[test]
  fn regexp_source_preserves_slash_inside_character_class() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        // `/` only needs escaping when it could terminate a RegExp literal. `/` inside a character
        // class is not a terminator and should be preserved.
        (/[/]/).source === "[/]" &&
        (/a\/b/).source === "a\\/b"
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_symbol_split_empty_string_match_returns_empty_array() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (function () {
          const parts = /(?:)/[Symbol.split]("");
          return Array.isArray(parts) && parts.length === 0;
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_replace_observes_result_groups_getter() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const r = /a/;
        r.exec = function () {
          return {
            0: "a",
            length: 1,
            index: 0,
            get groups() { throw "boom"; }
          };
        };
        let ok = false;
        try {
          r[Symbol.replace]("a", "x");
        } catch (e) {
          ok = (e === "boom");
        }
        ok
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_replace_observes_result_indices_getter() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const r = /a/d;
        r.exec = function () {
          return {
            0: "a",
            length: 1,
            index: 0,
            get indices() { throw "boom"; },
          };
        };
        let ok = false;
        try {
          r[Symbol.replace]("a", function () { return "x"; });
        } catch (e) {
          ok = (e === "boom");
        }
        ok
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_replace_passes_match_indices_and_supports_string_replacement() -> Result<(), VmError> {
    // Regression coverage for RegExp.prototype[@@replace] internal invariants:
    // - When the `d` (hasIndices) flag is enabled and a functional replacer is used, the `indices`
    //   value must be retrieved and passed to the replacer.
    // - When a string replacer is used, the replacement string must be available for
    //   `GetSubstitution`.
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (function () {
          let seen = false;
          const out1 = (/a/d)[Symbol.replace]("aba", function (m, pos, s, indices) {
            seen = Array.isArray(indices) &&
              indices.length === 1 &&
              indices[0][0] === pos &&
              indices[0][1] === pos + m.length;
            return "x";
          });
          const out2 = (/a/g)[Symbol.replace]("aba", "x");
          return seen && out1 === "xba" && out2 === "xbx";
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_replace_named_groups_are_used_by_get_substitution() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const r = /a/;
        r.exec = function () {
          return {
            0: "a",
            length: 1,
            index: 0,
            groups: { x: "b" }
          };
        };
        r[Symbol.replace]("a", "$<x>") === "b"
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }

  #[test]
  fn regexp_replace_functional_replace_passes_groups_arg() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        const r = /a/;
        r.exec = function () {
          return {
            0: "a",
            length: 1,
            index: 0,
            groups: { x: "b" }
          };
        };
        let got;
        r[Symbol.replace]("a", function () { got = arguments[arguments.length - 1]; return "x"; });
        got && got.x === "b"
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
}

#[cfg(test)]
mod async_generator_function_constructor_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn async_generator_function_dynamic_constructor_creates_function_object() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (function() {
          let AGF = (async function*(){}).constructor;

          // `%AsyncGeneratorFunction%` exists and is spec-shaped.
          if (typeof AGF !== "function") return false;
          if (AGF.name !== "AsyncGeneratorFunction") return false;
          if (AGF.length !== 1) return false;

          // Dynamic creation: `AsyncGeneratorFunction(params..., body)` returns a fresh async
          // generator function object, even though execution semantics are currently unimplemented.
          let f = AGF("a", "yield a;");
          if (typeof f !== "function") return false;
          if (f.name !== "anonymous") return false;
          if (f.length !== 1) return false;

          // `[[Prototype]]` is `%AsyncGeneratorFunction.prototype%`.
          if (Object.getPrototypeOf(f) !== AGF.prototype) return false;
          if (f.constructor !== AGF) return false;

          // Each async generator function gets its own `.prototype` whose `[[Prototype]]` is
          // `%AsyncGeneratorPrototype%` (reachable as `AsyncGeneratorFunction.prototype.prototype`).
          if (typeof f.prototype !== "object") return false;
          if (Object.getPrototypeOf(f.prototype) !== AGF.prototype.prototype) return false;
          // Spec: generator/async-generator per-function `.prototype` objects do *not* define an own
          // `constructor` property; it is inherited from `%AsyncGeneratorPrototype%` and points at
          // `%AsyncGeneratorFunction.prototype%`.
          if (Object.prototype.hasOwnProperty.call(f.prototype, "constructor")) return false;
          if (f.prototype.constructor !== AGF.prototype) return false;

          // Async generator functions are not constructors.
          try {
            new f();
            return false;
          } catch (e) {
            if (!(e instanceof TypeError)) return false;
          }

          // Syntax errors are thrown as catchable `SyntaxError` objects.
          try {
            AGF("a b", "");
            return false;
          } catch (e) {
            if (!(e instanceof SyntaxError)) return false;
          }

          // Strict-mode `with` is rejected at creation time by `CreateDynamicFunction`.
          try {
            AGF('"use strict"; with ({}) {}');
            return false;
          } catch (e) {
            if (!(e instanceof SyntaxError)) return false;
          }

          // `%AsyncGeneratorFunction.prototype%[@@toStringTag]`.
          if (Object.prototype.toString.call(f) !== "[object AsyncGeneratorFunction]") return false;

          return true;
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
}

#[cfg(test)]
mod async_generator_unit_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    // Async generator tests allocate Promise/job machinery; use a slightly larger heap than the
    // minimal 1MiB used by some unit tests to avoid spurious OOMs as builtin surface area grows.
    let heap = Heap::new(HeapLimits::new(4 * 1024 * 1024, 4 * 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  fn feature_detect_async_generators(rt: &mut JsRuntime) -> Result<bool, VmError> {
    match rt.exec_script(
      r#"
        async function* __ag_support() { yield 1; }
        __ag_support().next();
      "#,
    ) {
      Ok(_) => {
        // Avoid leaking Promise jobs into subsequent assertions within the same runtime.
        rt.teardown_microtasks();
        Ok(true)
      }
      Err(err) => {
        // Async generators are currently stubbed and may surface as either a raw `VmError::Unimplemented`
        // (internal callers) or a coerced `Throw*` at host boundaries.
        if is_unimplemented_async_generator_error(rt, &err)? {
          Ok(false)
        } else {
          Err(err)
        }
      }
    }
  }

  fn is_unimplemented_async_generator_error(rt: &mut JsRuntime, err: &VmError) -> Result<bool, VmError> {
    match err {
      VmError::Unimplemented(msg) => Ok(msg.contains("async generator functions")),
      VmError::Throw(_) | VmError::ThrowWithStack { .. } => {
        let Some(thrown) = err.thrown_value() else {
          return Ok(false);
        };
        let Value::Object(thrown_obj) = thrown else {
          return Ok(false);
        };

        // Root the thrown value while allocating property keys.
        let mut scope = rt.heap.scope();
        scope.push_root(thrown)?;

        let message_key = crate::PropertyKey::from_string(scope.alloc_string("message")?);
        let Some(message) = scope
          .heap()
          .object_get_own_data_property_value(thrown_obj, &message_key)?
        else {
          return Ok(false);
        };
        let Value::String(message_string) = message else {
          return Ok(false);
        };
        Ok(scope
          .heap()
          .get_string(message_string)?
          .to_utf8_lossy()
          .contains("async generator functions"))
      }
      _ => Ok(false),
    }
  }

  fn perform_microtask_checkpoint(rt: &mut JsRuntime) -> Result<(), VmError> {
    rt.vm.perform_microtask_checkpoint(&mut rt.heap)?;
    assert!(
      rt.vm.microtask_queue().is_empty(),
      "expected microtask queue to be empty after checkpoint"
    );
    Ok(())
  }

  #[test]
  fn next_returns_intrinsic_promise() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let result: Result<(), VmError> = (|| {
      if !feature_detect_async_generators(&mut rt)? {
        return Ok(());
      }
      let v = rt.exec_script(
        r#"
          (function () {
            var P0 = Promise;
            Promise = function FakePromise(executor) { throw "should not be called"; };

            async function* g() { yield 1; }
            var p = g().next();

            // `AsyncGenerator.prototype.next` must use `NewPromiseCapability(%Promise%)`, not the
            // mutable global `Promise` binding.
            return Object.getPrototypeOf(p) === P0.prototype;
          })()
        "#,
      )?;
      assert_eq!(v, Value::Bool(true));
      // Run the `next()` job to avoid leaking queued microtasks.
      perform_microtask_checkpoint(&mut rt)?;
      Ok(())
    })();
    rt.teardown_microtasks();
    result
  }

  #[test]
  fn next_promise_resolves_to_value_done() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let result: Result<(), VmError> = (|| {
      if !feature_detect_async_generators(&mut rt)? {
        return Ok(());
      }
      rt.exec_script(
        r#"
          var got = undefined;
          async function* g() { yield 1; }
          g().next().then(function (r) { got = [r.value, r.done]; });
        "#,
      )?;

      perform_microtask_checkpoint(&mut rt)?;

      let v = rt.exec_script("got && got[0] === 1 && got[1] === false")?;
      assert_eq!(v, Value::Bool(true));
      Ok(())
    })();
    rt.teardown_microtasks();
    result
  }

  #[test]
  fn throw_on_suspended_start_rejects_without_executing_body() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let result: Result<(), VmError> = (|| {
      if !feature_detect_async_generators(&mut rt)? {
        return Ok(());
      }
      rt.exec_script(
        r#"
          var started = false;
          var rejected = false;
          var reason = undefined;

          async function* g() { started = true; yield 1; }
          var it = g();
          it.throw(123).then(
            function () { rejected = false; },
            function (e) { rejected = true; reason = e; }
          );
        "#,
      )?;

      perform_microtask_checkpoint(&mut rt)?;

      let v = rt.exec_script("rejected === true && reason === 123 && started === false")?;
      assert_eq!(v, Value::Bool(true));
      Ok(())
    })();
    rt.teardown_microtasks();
    result
  }

  #[test]
  fn return_on_completed_awaits_and_fulfills_done_true() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let result: Result<(), VmError> = (|| {
      if !feature_detect_async_generators(&mut rt)? {
        return Ok(());
      }
      rt.exec_script(
        r#"
          var ret = undefined;

          async function* g() {}
          var it = g();

          // Complete the generator, then call `.return()` with a Promise that must be awaited.
          it.next().then(function () {
            it.return(Promise.resolve(7)).then(function (r) { ret = [r.value, r.done]; });
          });
        "#,
      )?;

      perform_microtask_checkpoint(&mut rt)?;

      let v = rt.exec_script("ret && ret[0] === 7 && ret[1] === true")?;
      assert_eq!(v, Value::Bool(true));
      Ok(())
    })();
    rt.teardown_microtasks();
    result
  }
}

#[cfg(test)]
mod dynamic_function_constructor_body_empty_tests {
  use crate::{Heap, HeapLimits, JsRuntime, Value, Vm, VmError, VmOptions};

  fn new_runtime() -> JsRuntime {
    let vm = Vm::new(VmOptions::default());
    let heap = Heap::new(HeapLimits::new(1024 * 1024, 1024 * 1024));
    JsRuntime::new(vm, heap).unwrap()
  }

  #[test]
  fn dynamic_function_constructors_use_empty_body_when_no_args() -> Result<(), VmError> {
    let mut rt = new_runtime();
    let v = rt.exec_script(
      r#"
        (function() {
          // Ordinary functions.
          const f0 = Function();
          if (f0.toString() !== "function anonymous(\n) {\n\n}") return false;

          // Generator functions.
          const gf0 = (function*(){}).constructor();
          if (gf0.toString() !== "function* anonymous(\n) {\n\n}") return false;

          // Async generator functions.
          const AGF = (async function*(){}).constructor;
          const agf0 = AGF();
          if (agf0.toString() !== "async function* anonymous(\n) {\n\n}") return false;

          // `undefined` body is still `ToString(undefined)` when provided explicitly.
          const fU = Function(undefined);
          if (fU.toString() !== "function anonymous(\n) {\nundefined\n}") return false;

          return true;
        })()
      "#,
    )?;
    assert_eq!(v, Value::Bool(true));
    Ok(())
  }
}
